SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the energy level diagram of hydrogen atom with transitions labelled P, Q, R, and S. Transition P is from n=4 to n=2, Q from n=3 to n=1, R from n=5 to n=3, and S from n=3 to n=2. Which transition emits a photon of the longest wavelength?", "explanation": "Longest wavelength corresponds to smallest energy difference. S (n=3→2) has ΔE = 13.6(1/4−1/9) = 1.89 eV, R (n=5→3) has ΔE = 13.6(1/9−1/25) = 0.97 eV. So R emits the longest wavelength. Generally, transitions between higher levels with smaller gaps give longer wavelengths.", "payload": {"question_id": "cuet-phy-atom-bohr-d01", "subtopic": "Energy level transitions", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "Transition P", "is_correct": false}, {"key": "B", "text": "Transition Q", "is_correct": false}, {"key": "C", "text": "Transition R", "is_correct": true}, {"key": "D", "text": "Transition S", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P (n=4→2) belongs to Balmer series with ΔE ≈ 2.55 eV — shorter wavelength than R.", "misconception": "Confusing higher initial level with longer wavelength"}, {"option_key": "B", "hint": "Q (n=3→1) belongs to Lyman series with ΔE ≈ 12.09 eV — this gives UV radiation, the shortest wavelength here.", "misconception": "Thinking transitions to ground state give longer wavelengths"}, {"option_key": "D", "hint": "S (n=3→2) has ΔE ≈ 1.89 eV. R (n=5→3) has ΔE ≈ 0.97 eV, which is smaller, so R has longer λ.", "misconception": null}], "image_uri": "diagrams/cuet-phy-atom-bohr-d01.png", "image_alt": "Energy level diagram of hydrogen showing four transitions: P (n=4→2), Q (n=3→1), R (n=5→3), S (n=3→2)"}, "image_alt": "Energy level diagram of hydrogen showing four transitions: P (n=4→2), Q (n=3→1), R (n=5→3), S (n=3→2)", "correct_answer": "C", "concept_tags": ["energy-levels", "photon-wavelength", "hydrogen-spectrum"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows circular orbits of an electron in a hydrogen atom according to Bohr''s model. If r₁ is the radius of the first orbit, what is the radius of the orbit labelled n=3?", "explanation": "In Bohr''s model, rₙ = n²r₁. For n=3, r₃ = 9r₁. The radii increase as the square of the principal quantum number.", "payload": {"question_id": "cuet-phy-atom-bohr-d02", "subtopic": "Bohr orbit radii", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "3r₁", "is_correct": false}, {"key": "B", "text": "6r₁", "is_correct": false}, {"key": "C", "text": "8r₁", "is_correct": false}, {"key": "D", "text": "9r₁", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "3r₁ assumes rₙ ∝ n, but Bohr''s model gives rₙ ∝ n².", "misconception": "Thinking radius is directly proportional to n"}, {"option_key": "B", "hint": "6r₁ = 2×3×r₁ has no physical basis in the Bohr model formula.", "misconception": null}, {"option_key": "C", "hint": "8r₁ = 2³r₁ confuses the n² dependence with n³.", "misconception": "Confusing quadratic with cubic dependence"}], "image_uri": "diagrams/cuet-phy-atom-bohr-d02.png", "image_alt": "Concentric circular orbits around a nucleus labelled n=1, n=2, n=3 with increasing radii"}, "image_alt": "Concentric circular orbits around a nucleus labelled n=1, n=2, n=3 with increasing radii", "correct_answer": "D", "concept_tags": ["bohr-radius", "orbit-radius", "quantization"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following spectral series of hydrogen in order of increasing wavelength of their first line:\n(I) Lyman series\n(II) Balmer series\n(III) Paschen series\n(IV) Brackett series", "explanation": "The first line of each series: Lyman (n=2→1, λ=121.6 nm), Balmer (n=3→2, λ=656.3 nm), Paschen (n=4→3, λ=1875 nm), Brackett (n=5→4, λ=4051 nm). Order of increasing wavelength: Lyman < Balmer < Paschen < Brackett.", "payload": {"question_id": "cuet-phy-atom-bohr-ls01", "subtopic": "Spectral series ordering", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "understand", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III → IV", "is_correct": false}, {"key": "D", "text": "I → III → II → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing wavelength, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Lyman series has the shortest wavelength (UV), not Balmer.", "misconception": "Thinking visible light has shorter wavelength than UV"}, {"option_key": "D", "hint": "Balmer (visible) has shorter wavelength than Paschen (IR), so II should come before III.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["spectral-series", "wavelength-order", "hydrogen-spectrum"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows an emission spectrum with bright lines on a dark background and an absorption spectrum with dark lines on a bright background. If the emission spectrum is of sodium vapour, what does the absorption spectrum show?", "explanation": "Kirchhoff''s law states that a substance absorbs the same wavelengths it emits. Sodium emits characteristic yellow D-lines (589.0 nm and 589.6 nm). When white light passes through sodium vapour, these exact wavelengths are absorbed, creating dark lines at the same positions.", "payload": {"question_id": "cuet-phy-atom-spectra-d01", "subtopic": "Emission and absorption spectra", "topic_name": "Atomic Spectra", "bloom_level": "understand", "options": [{"key": "A", "text": "Dark lines at completely different positions from the emission lines", "is_correct": false}, {"key": "B", "text": "Dark lines at exactly the same positions as the emission lines", "is_correct": true}, {"key": "C", "text": "A continuous spectrum with no dark lines", "is_correct": false}, {"key": "D", "text": "Dark lines that shift to longer wavelengths", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Absorption occurs at the same wavelengths that are emitted — this is Kirchhoff''s spectroscopic law.", "misconception": "Thinking emission and absorption wavelengths differ"}, {"option_key": "C", "hint": "If sodium vapour is present, it will absorb its characteristic wavelengths — dark lines must appear.", "misconception": "Ignoring absorption by the gas"}, {"option_key": "D", "hint": "Absorption lines appear at the same wavelength as emission. A red-shift occurs due to relative motion (Doppler), not absorption.", "misconception": "Confusing Doppler shift with absorption"}], "image_uri": "diagrams/cuet-phy-atom-spectra-d01.png", "image_alt": "Top: emission spectrum with bright yellow lines (D1, D2) on dark background. Bottom: absorption spectrum with dark lines at same positions on continuous bright background."}, "image_alt": "Top: emission spectrum with bright yellow lines (D1, D2) on dark background. Bottom: absorption spectrum with dark lines at same positions on continuous bright background.", "correct_answer": "B", "concept_tags": ["emission-spectrum", "absorption-spectrum", "kirchhoff-law"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The graph shows the variation of 1/λ (inverse wavelength) versus 1/n² for a spectral series of hydrogen, where n is the principal quantum number of the upper level. The graph is a straight line. What is the y-intercept of this line for the Balmer series?", "explanation": "For Balmer series: 1/λ = R(1/2² − 1/n²) = R/4 − R/n². Plotting 1/λ vs 1/n² gives a straight line with slope −R and y-intercept R/4 where R is the Rydberg constant (1.097 × 10⁷ m⁻¹). So y-intercept = R/4 ≈ 2.74 × 10⁶ m⁻¹.", "payload": {"question_id": "cuet-phy-atom-spectra-d02", "subtopic": "Rydberg formula graphical analysis", "topic_name": "Atomic Spectra", "bloom_level": "analyze", "options": [{"key": "A", "text": "R/4", "is_correct": true}, {"key": "B", "text": "R", "is_correct": false}, {"key": "C", "text": "R/9", "is_correct": false}, {"key": "D", "text": "4R", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R would be the y-intercept for the Lyman series (1/1² = 1), not Balmer.", "misconception": "Using n=1 instead of n=2 for Balmer series"}, {"option_key": "C", "hint": "R/9 = R/3² would apply to the Paschen series, not Balmer.", "misconception": "Confusing Paschen (n₁=3) with Balmer (n₁=2)"}, {"option_key": "D", "hint": "4R has incorrect dimensions/value — the y-intercept is R divided by n₁², not multiplied.", "misconception": "Inverting the formula"}], "image_uri": "diagrams/cuet-phy-atom-spectra-d02.png", "image_alt": "Linear graph of 1/λ (y-axis) vs 1/n² (x-axis) with negative slope, showing data points for n=3,4,5,6"}, "image_alt": "Linear graph of 1/λ (y-axis) vs 1/n² (x-axis) with negative slope, showing data points for n=3,4,5,6", "correct_answer": "A", "concept_tags": ["rydberg-formula", "balmer-series", "graphical-analysis"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following atomic models in chronological order of their proposal:\n(I) Rutherford''s nuclear model\n(II) Thomson''s plum pudding model\n(III) Bohr''s quantized orbit model\n(IV) Quantum mechanical model", "explanation": "Thomson (1904) → Rutherford (1911) → Bohr (1913) → Quantum mechanical/Schrödinger (1926). Each model addressed limitations of its predecessor.", "payload": {"question_id": "cuet-phy-atom-spectra-ls01", "subtopic": "Historical development of atomic models", "topic_name": "Atomic Spectra", "bloom_level": "remember", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": false}, {"key": "B", "text": "II → I → III → IV", "is_correct": true}, {"key": "C", "text": "II → III → I → IV", "is_correct": false}, {"key": "D", "text": "III → II → I → IV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Thomson''s model came before Rutherford''s — the alpha scattering experiment disproved the plum pudding model.", "misconception": "Thinking Rutherford''s model came first"}, {"option_key": "C", "hint": "Bohr''s model was proposed after Rutherford''s to explain atomic stability and spectral lines.", "misconception": "Reversing Rutherford and Bohr chronology"}, {"option_key": "D", "hint": "Bohr''s model (1913) came after Thomson''s (1904), not before.", "misconception": null}]}, "image_alt": null, "correct_answer": "B", "concept_tags": ["atomic-models", "history-of-physics", "chronology"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-radioactivity", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the radioactive decay curve (N/N₀ vs t) for a substance. From the graph, if after 20 minutes the fraction remaining is 1/4, what is the half-life of the substance?", "explanation": "If N/N₀ = 1/4 = (1/2)² after 20 minutes, then 2 half-lives have elapsed. Therefore t₁/₂ = 20/2 = 10 minutes.", "payload": {"question_id": "cuet-phy-nuclei-decay-d01", "subtopic": "Half-life from decay curve", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "5 minutes", "is_correct": false}, {"key": "B", "text": "10 minutes", "is_correct": true}, {"key": "C", "text": "20 minutes", "is_correct": false}, {"key": "D", "text": "40 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If t₁/₂ = 5 min, then in 20 min there would be 4 half-lives, giving N/N₀ = 1/16, not 1/4.", "misconception": null}, {"option_key": "C", "hint": "20 minutes is the total time for N/N₀ to reach 1/4 (two half-lives), not the half-life itself.", "misconception": "Confusing total decay time with half-life"}, {"option_key": "D", "hint": "If t₁/₂ = 40 min, then 20 min would be only half a half-life, giving N/N₀ = 1/√2 ≈ 0.707, not 0.25.", "misconception": null}], "image_uri": "diagrams/cuet-phy-nuclei-decay-d01.png", "image_alt": "Exponential decay curve showing N/N₀ on y-axis (1 to 0) and time t on x-axis. Curve passes through (0,1), (10, 0.5), (20, 0.25), (30, 0.125)"}, "image_alt": "Exponential decay curve showing N/N₀ on y-axis (1 to 0) and time t on x-axis. Curve passes through (0,1), (10, 0.5), (20, 0.25), (30, 0.125)", "correct_answer": "B", "concept_tags": ["half-life", "decay-curve", "radioactive-decay"]}]'::jsonb, 'correction-batch-1');

