SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-radioactivity", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows a decay chain on an N-Z plot (neutron number vs proton number). A nucleus X undergoes α-decay followed by two successive β⁻ decays to reach nucleus Y. If X has (Z, N) = (92, 146), what are the coordinates of Y?", "explanation": "α-decay: Z→Z−2, N→N−2 (loses 2p + 2n). After α: (90, 144). β⁻ decay: Z→Z+1, N→N−1 (neutron converts to proton). After first β⁻: (91, 143). After second β⁻: (92, 142). So Y = (92, 142).", "payload": {"question_id": "cuet-phy-nuclei-decay-d02", "subtopic": "Decay chains on N-Z plot", "topic_name": "Radioactive Decay", "bloom_level": "analyze", "options": [{"key": "A", "text": "(90, 144)", "is_correct": false}, {"key": "B", "text": "(90, 142)", "is_correct": false}, {"key": "C", "text": "(91, 143)", "is_correct": false}, {"key": "D", "text": "(92, 142)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the position after α-decay only — you still need to apply two β⁻ decays.", "misconception": "Forgetting the β⁻ decay steps"}, {"option_key": "B", "hint": "This would be correct if β⁻ only changed N without changing Z, but β⁻ increases Z by 1 each time.", "misconception": "Ignoring proton number change in β⁻ decay"}, {"option_key": "C", "hint": "This is the position after α + one β⁻ — you need one more β⁻ decay.", "misconception": "Applying only one β⁻ instead of two"}], "image_uri": "diagrams/cuet-phy-nuclei-decay-d02.png", "image_alt": "N-Z plot showing nucleus X at (92,146), α-decay arrow going to (90,144), then two β⁻ arrows each going right by 1 in Z and down by 1 in N"}, "image_alt": "N-Z plot showing nucleus X at (92,146), α-decay arrow going to (90,144), then two β⁻ arrows each going right by 1 in Z and down by 1 in N", "correct_answer": "D", "concept_tags": ["alpha-decay", "beta-decay", "NZ-plot", "decay-chain"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-radioactivity", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following types of radiation in order of increasing penetrating power:\n(I) Alpha particles\n(II) Gamma rays\n(III) Beta particles", "explanation": "Alpha particles are stopped by a sheet of paper (least penetrating). Beta particles penetrate a few mm of aluminium. Gamma rays can penetrate several cm of lead (most penetrating). Order: α < β < γ.", "payload": {"question_id": "cuet-phy-nuclei-decay-ls01", "subtopic": "Properties of nuclear radiation", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "I → III → II", "is_correct": true}, {"key": "B", "text": "II → III → I", "is_correct": false}, {"key": "C", "text": "III → I → II", "is_correct": false}, {"key": "D", "text": "I → II → III", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing penetrating power, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Beta particles are more penetrating than alpha, and gamma is most penetrating.", "misconception": null}, {"option_key": "D", "hint": "Gamma rays are more penetrating than beta particles — they need thick lead shielding.", "misconception": "Confusing ionizing power with penetrating power"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["penetrating-power", "radiation-types", "alpha-beta-gamma"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-nucleus", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows binding energy per nucleon (BE/A) versus mass number (A). Which region of the curve corresponds to nuclei that can release energy by nuclear fission?", "explanation": "Nuclear fission releases energy when heavy nuclei (A > 200, like U-235) split into medium-mass fragments with higher BE/A. The right side of the curve (heavy nuclei) has lower BE/A than the middle, so splitting them releases the difference in binding energy.", "payload": {"question_id": "cuet-phy-nuclei-prop-d01", "subtopic": "Binding energy curve and fission", "topic_name": "Nuclear Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Light nuclei (A < 20)", "is_correct": false}, {"key": "B", "text": "Medium nuclei near the peak (A ≈ 56)", "is_correct": false}, {"key": "C", "text": "All nuclei along the curve", "is_correct": false}, {"key": "D", "text": "Heavy nuclei (A > 200)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Light nuclei release energy by fusion (moving up the curve), not fission.", "misconception": "Confusing fusion with fission"}, {"option_key": "B", "hint": "Nuclei near the peak (like Fe-56) are the most stable — they cannot release energy by either fission or fusion.", "misconception": "Thinking the most stable nuclei undergo fission"}, {"option_key": "C", "hint": "Only nuclei on the declining right side can release energy by fission. Light nuclei release energy by fusion instead.", "misconception": null}], "image_uri": "diagrams/cuet-phy-nuclei-prop-d01.png", "image_alt": "BE/A vs A curve showing rise to peak around A=56 (Fe), then gradual decline. Regions marked: light nuclei (left), medium nuclei (peak), heavy nuclei (right)"}, "image_alt": "BE/A vs A curve showing rise to peak around A=56 (Fe), then gradual decline. Regions marked: light nuclei (left), medium nuclei (peak), heavy nuclei (right)", "correct_answer": "D", "concept_tags": ["binding-energy", "nuclear-fission", "mass-number"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-nucleus", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a schematic of a nucleus with protons (marked +) and neutrons (marked n). If the nucleus shown has 6 protons and 8 neutrons, which element is it and what is its mass number?", "explanation": "The element is determined by atomic number Z = number of protons = 6, which is Carbon. Mass number A = Z + N = 6 + 8 = 14. So the nucleus is Carbon-14 (¹⁴C), a radioactive isotope used in carbon dating.", "payload": {"question_id": "cuet-phy-nuclei-prop-d02", "subtopic": "Nuclear composition", "topic_name": "Nuclear Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Nitrogen-14 (A = 14)", "is_correct": false}, {"key": "B", "text": "Carbon-12 (A = 12)", "is_correct": false}, {"key": "C", "text": "Carbon-14 (A = 14)", "is_correct": true}, {"key": "D", "text": "Oxygen-14 (A = 14)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nitrogen has Z = 7, but the diagram shows only 6 protons.", "misconception": "Counting nucleons incorrectly"}, {"option_key": "B", "hint": "Carbon-12 has 6 protons and 6 neutrons (A = 12), but the diagram shows 8 neutrons.", "misconception": "Assuming equal protons and neutrons"}, {"option_key": "D", "hint": "Oxygen has Z = 8, not Z = 6.", "misconception": "Confusing atomic numbers of C and O"}], "image_uri": "diagrams/cuet-phy-nuclei-prop-d02.png", "image_alt": "Circular cluster showing 6 particles marked ''+'' (protons) and 8 particles marked ''n'' (neutrons) packed together"}, "image_alt": "Circular cluster showing 6 particles marked ''+'' (protons) and 8 particles marked ''n'' (neutrons) packed together", "correct_answer": "C", "concept_tags": ["atomic-number", "mass-number", "nuclear-composition"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-nucleus", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following nuclear reactions in order of the energy released per nucleon (lowest to highest):\n(I) Nuclear fission of U-235\n(II) Nuclear fusion of hydrogen to helium\n(III) Chemical combustion of coal\n(IV) Nuclear fission of Pu-239", "explanation": "Chemical combustion releases ~few eV per molecule ≈ negligible per nucleon. U-235 fission releases ~200 MeV / 236 ≈ 0.85 MeV/nucleon. Pu-239 fission releases ~210 MeV / 240 ≈ 0.88 MeV/nucleon. H→He fusion releases ~26.7 MeV / 4 ≈ 6.7 MeV/nucleon. Order: III < I < IV < II.", "payload": {"question_id": "cuet-phy-nuclei-prop-ls01", "subtopic": "Energy release comparison", "topic_name": "Nuclear Properties", "bloom_level": "analyze", "options": [{"key": "A", "text": "III → II → I → IV", "is_correct": false}, {"key": "B", "text": "III → I → IV → II", "is_correct": true}, {"key": "C", "text": "I → III → IV → II", "is_correct": false}, {"key": "D", "text": "III → IV → I → II", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Fusion releases far more energy per nucleon than fission — it should be last, not second.", "misconception": "Thinking total energy equals energy per nucleon"}, {"option_key": "C", "hint": "Chemical reactions release orders of magnitude less energy than nuclear reactions.", "misconception": "Overestimating chemical energy relative to nuclear energy"}, {"option_key": "D", "hint": "U-235 and Pu-239 release similar energy per nucleon, with Pu-239 slightly higher.", "misconception": null}]}, "image_alt": null, "correct_answer": "B", "concept_tags": ["energy-per-nucleon", "fission-vs-fusion", "nuclear-energy"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The graph shows V-I characteristics of two conductors A and B. Conductor A has a steeper slope than B. Which conductor has greater resistance?", "explanation": "From Ohm''s law, V = IR, so in a V vs I graph, the slope equals R. A steeper slope means greater resistance. Conductor A has the steeper line, so it has greater resistance.", "payload": {"question_id": "cuet-phy-current-ohm-d01", "subtopic": "V-I characteristics", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Conductor A", "is_correct": true}, {"key": "B", "text": "Conductor B", "is_correct": false}, {"key": "C", "text": "Both have equal resistance", "is_correct": false}, {"key": "D", "text": "Cannot be determined from the graph", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "B has a gentler slope, meaning lower V for the same I, so lower resistance.", "misconception": "Confusing slope with inverse slope"}, {"option_key": "C", "hint": "The slopes are clearly different, so the resistances must be different.", "misconception": null}, {"option_key": "D", "hint": "For ohmic conductors, R = slope of V vs I graph — it is directly readable.", "misconception": null}], "image_uri": "diagrams/cuet-phy-current-ohm-d01.png", "image_alt": "V-I graph with two straight lines through origin: line A with steep slope, line B with gentler slope. V on y-axis, I on x-axis."}, "image_alt": "V-I graph with two straight lines through origin: line A with steep slope, line B with gentler slope. V on y-axis, I on x-axis.", "correct_answer": "A", "concept_tags": ["ohms-law", "V-I-characteristics", "resistance"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a circuit with three resistors: R₁ = 2Ω and R₂ = 4Ω in parallel, and this combination in series with R₃ = 3Ω, connected to a 12V battery. What is the total current from the battery?", "explanation": "Parallel combination of R₁ and R₂: 1/Rp = 1/2 + 1/4 = 3/4, so Rp = 4/3 Ω. Total resistance: R = R₃ + Rp = 3 + 4/3 = 13/3 Ω. Current I = V/R = 12/(13/3) = 36/13 ≈ 2.77 A.", "payload": {"question_id": "cuet-phy-current-ohm-d02", "subtopic": "Series-parallel combinations", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "4 A", "is_correct": false}, {"key": "B", "text": "2 A", "is_correct": false}, {"key": "C", "text": "36/13 A ≈ 2.77 A", "is_correct": true}, {"key": "D", "text": "12/9 A ≈ 1.33 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4 A would mean total R = 3 Ω, ignoring the parallel combination entirely.", "misconception": "Using only R₃ as total resistance"}, {"option_key": "B", "hint": "2 A would mean total R = 6 Ω, which is R₁ + R₂ (series) not R₁ ∥ R₂.", "misconception": "Adding parallel resistors as if in series"}, {"option_key": "D", "hint": "12/9 would mean total R = 9 = 2+4+3, treating all three as series.", "misconception": "Treating all resistors as in series"}], "image_uri": "diagrams/cuet-phy-current-ohm-d02.png", "image_alt": "Circuit: 12V battery connected to R3=3Ω in series, then R1=2Ω and R2=4Ω in parallel"}, "image_alt": "Circuit: 12V battery connected to R3=3Ω in series, then R1=2Ω and R2=4Ω in parallel", "correct_answer": "C", "concept_tags": ["series-parallel", "total-resistance", "circuit-analysis"]}]'::jsonb, 'correction-batch-1');

-- correction-batch-1 questions 15-21
SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following materials in order of increasing resistivity:\n(I) Copper\n(II) Nichrome\n(III) Silicon\n(IV) Glass", "explanation": "Resistivity order: Copper (1.7×10⁻⁸ Ω·m, conductor) < Nichrome (1.1×10⁻⁶ Ω·m, alloy) < Silicon (6.4×10² Ω·m, semiconductor) < Glass (10¹⁰–10¹⁴ Ω·m, insulator).", "payload": {"question_id": "cuet-phy-current-ohm-ls01", "subtopic": "Resistivity of materials", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → III → II → IV", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing resistivity, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Nichrome is an alloy with much lower resistivity than silicon (a semiconductor).", "misconception": "Thinking semiconductors have lower resistivity than alloys"}, {"option_key": "D", "hint": "Copper is a better conductor than nichrome — it has lower resistivity.", "misconception": "Confusing conductivity ranking of pure metals and alloys"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["resistivity", "conductors", "semiconductors", "insulators"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a Wheatstone bridge with P = 100Ω, Q = 200Ω, R = 150Ω, and S unknown. The galvanometer shows zero deflection. What is the value of S?", "explanation": "At balance, P/Q = R/S. So 100/200 = 150/S. Therefore S = 150 × 200/100 = 300Ω.", "payload": {"question_id": "cuet-phy-current-kirch-d01", "subtopic": "Wheatstone bridge balance", "topic_name": "Kirchhoff''s Laws", "bloom_level": "apply", "options": [{"key": "A", "text": "75 Ω", "is_correct": false}, {"key": "B", "text": "100 Ω", "is_correct": false}, {"key": "C", "text": "200 Ω", "is_correct": false}, {"key": "D", "text": "300 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "75 Ω would give P/Q = 1/2 but R/S = 150/75 = 2 — not balanced.", "misconception": "Using P×Q = R×S instead of P/Q = R/S"}, {"option_key": "B", "hint": "100 Ω gives R/S = 3/2 ≠ P/Q = 1/2.", "misconception": null}, {"option_key": "C", "hint": "200 Ω gives R/S = 3/4 ≠ P/Q = 1/2.", "misconception": null}], "image_uri": "diagrams/cuet-phy-current-kirch-d01.png", "image_alt": "Wheatstone bridge circuit with P=100Ω, Q=200Ω on top arms, R=150Ω, S=? on bottom arms, galvanometer in middle"}, "image_alt": "Wheatstone bridge circuit with P=100Ω, Q=200Ω on top arms, R=150Ω, S=? on bottom arms, galvanometer in middle", "correct_answer": "D", "concept_tags": ["wheatstone-bridge", "balanced-condition", "resistance-measurement"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The circuit diagram shows two loops. Loop 1 has a 10V battery and resistors of 2Ω and 3Ω. Loop 2 shares the 3Ω resistor and has a 5V battery with a 4Ω resistor. Using Kirchhoff''s voltage law, what is the current through the 3Ω resistor?", "explanation": "Let I₁ flow in loop 1, I₂ in loop 2 (both clockwise). Current through 3Ω = I₁ − I₂. Loop 1: 10 = 2I₁ + 3(I₁−I₂) → 5I₁ − 3I₂ = 10. Loop 2: 5 = 4I₂ + 3(I₂−I₁) → −3I₁ + 7I₂ = 5. Solving: I₁ = 95/26, I₂ = 55/26. Current through 3Ω = 40/26 = 20/13 ≈ 1.54 A.", "payload": {"question_id": "cuet-phy-current-kirch-d02", "subtopic": "Multi-loop circuit analysis", "topic_name": "Kirchhoff''s Laws", "bloom_level": "analyze", "options": [{"key": "A", "text": "2 A", "is_correct": false}, {"key": "B", "text": "20/13 A ≈ 1.54 A", "is_correct": true}, {"key": "C", "text": "1 A", "is_correct": false}, {"key": "D", "text": "15/7 A ≈ 2.14 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2 A would be the current if only one battery existed. With two batteries, mesh analysis is needed.", "misconception": "Ignoring the second loop"}, {"option_key": "C", "hint": "1 A is too simple an answer for a two-loop circuit — it doesn''t account for the interaction between loops.", "misconception": null}, {"option_key": "D", "hint": "15/7 arises from incorrect loop equations or wrong sign convention.", "misconception": "Sign error in Kirchhoff''s voltage law"}], "image_uri": "diagrams/cuet-phy-current-kirch-d02.png", "image_alt": "Two-loop circuit: Loop 1 with 10V battery, 2Ω and 3Ω. Loop 2 with 5V battery, 4Ω sharing the 3Ω with Loop 1"}, "image_alt": "Two-loop circuit: Loop 1 with 10V battery, 2Ω and 3Ω. Loop 2 with 5V battery, 4Ω sharing the 3Ω with Loop 1", "correct_answer": "B", "concept_tags": ["kirchhoff-voltage-law", "mesh-analysis", "simultaneous-equations"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following steps for solving a circuit using Kirchhoff''s laws:\n(I) Apply KVL around each independent loop\n(II) Assign current directions in each branch\n(III) Apply KCL at each junction\n(IV) Solve the simultaneous equations", "explanation": "The systematic approach: First assign current directions (II), then apply junction rule KCL (III), then apply loop rule KVL (I), finally solve the resulting equations (IV).", "payload": {"question_id": "cuet-phy-current-kirch-ls01", "subtopic": "Method of solving circuits", "topic_name": "Kirchhoff''s Laws", "bloom_level": "understand", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": false}, {"key": "B", "text": "III → II → I → IV", "is_correct": false}, {"key": "C", "text": "II → III → I → IV", "is_correct": true}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You must assign currents before writing KVL equations — you need variable names first.", "misconception": "Trying to write equations without defining variables"}, {"option_key": "B", "hint": "KCL at junctions requires knowing current directions first.", "misconception": null}, {"option_key": "D", "hint": "KCL at junctions is typically applied before KVL to reduce the number of unknowns.", "misconception": "Applying KVL before KCL"}]}, "image_alt": null, "correct_answer": "C", "concept_tags": ["kirchhoff-laws", "circuit-solving", "systematic-method"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-wheatstone", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a meter bridge in balance. The balance point is at 40 cm from the left end. If the known resistance R = 6Ω, what is the unknown resistance X?", "explanation": "At balance: X/R = l/(100−l) = 40/60 = 2/3. So X = R × 2/3 = 6 × 2/3 = 4Ω.", "payload": {"question_id": "cuet-phy-current-instr-d01", "subtopic": "Meter bridge", "topic_name": "Electrical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "9 Ω", "is_correct": false}, {"key": "B", "text": "4 Ω", "is_correct": true}, {"key": "C", "text": "6 Ω", "is_correct": false}, {"key": "D", "text": "2.4 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "9 Ω would give X/R = 9/6 = 3/2, requiring balance at 60 cm, not 40 cm.", "misconception": "Inverting the ratio l/(100-l)"}, {"option_key": "C", "hint": "X = R = 6Ω would require balance at 50 cm (midpoint).", "misconception": null}, {"option_key": "D", "hint": "2.4 Ω comes from an incorrect formula.", "misconception": null}], "image_uri": "diagrams/cuet-phy-current-instr-d01.png", "image_alt": "Meter bridge setup with jockey at 40cm mark, R=6Ω on left gap, X on right gap, galvanometer connected"}, "image_alt": "Meter bridge setup with jockey at 40cm mark, R=6Ω on left gap, X on right gap, galvanometer connected", "correct_answer": "B", "concept_tags": ["meter-bridge", "wheatstone-principle", "resistance-measurement"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-potentiometer", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a potentiometer circuit. A standard cell of EMF 1.02 V balances at length 51 cm. An unknown EMF balances at 75 cm. What is the unknown EMF?", "explanation": "In a potentiometer, EMF ∝ balancing length. E_unknown/E_standard = l₂/l₁ = 75/51. So E_unknown = 1.02 × 75/51 = 1.5 V.", "payload": {"question_id": "cuet-phy-current-instr-d02", "subtopic": "Potentiometer", "topic_name": "Electrical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "0.693 V", "is_correct": false}, {"key": "B", "text": "1.02 V", "is_correct": false}, {"key": "C", "text": "1.5 V", "is_correct": true}, {"key": "D", "text": "2.04 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.693 V = 1.02 × 51/75 — you inverted the ratio.", "misconception": "Using l₁/l₂ instead of l₂/l₁"}, {"option_key": "B", "hint": "The unknown balances at a longer length, so its EMF must be greater than 1.02 V.", "misconception": "Thinking both EMFs are equal"}, {"option_key": "D", "hint": "2.04 V = 2 × 1.02 would need balance at 102 cm, which exceeds the wire length.", "misconception": null}], "image_uri": "diagrams/cuet-phy-current-instr-d02.png", "image_alt": "Potentiometer wire with driver cell, galvanometer, standard cell balancing at 51cm and unknown cell at 75cm"}, "image_alt": "Potentiometer wire with driver cell, galvanometer, standard cell balancing at 51cm and unknown cell at 75cm", "correct_answer": "C", "concept_tags": ["potentiometer", "emf-comparison", "balancing-length"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-curr-wheatstone", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps for measuring unknown resistance using a meter bridge:\n(I) Note the balancing length\n(II) Connect the unknown resistance and known resistance in the gaps\n(III) Calculate X using X/R = l/(100−l)\n(IV) Slide the jockey along the wire until galvanometer shows null deflection", "explanation": "First connect the resistances (II), then slide jockey to find null point (IV), note the length (I), and finally calculate (III).", "payload": {"question_id": "cuet-phy-current-instr-ls01", "subtopic": "Meter bridge procedure", "topic_name": "Electrical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "II → IV → I → III", "is_correct": true}, {"key": "B", "text": "I → II → IV → III", "is_correct": false}, {"key": "C", "text": "II → I → IV → III", "is_correct": false}, {"key": "D", "text": "IV → II → III → I", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "You can''t note the balancing length before connecting the resistances and finding balance.", "misconception": null}, {"option_key": "C", "hint": "You must find the null point (IV) before noting the length (I).", "misconception": "Noting length before finding balance"}, {"option_key": "D", "hint": "You can''t slide the jockey before connecting the circuit.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["meter-bridge", "experimental-procedure", "resistance-measurement"]}]'::jsonb, 'correction-batch-1');

-- correction-batch-2 questions 1-7
SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the variation of de Broglie wavelength (λ) with accelerating potential (V) for an electron. Which of the following best describes the nature of this curve?", "explanation": "For an electron accelerated through potential V: λ = h/√(2meV) = 1.226/√V nm. So λ ∝ 1/√V, giving a rectangular hyperbola that decreases steeply at low V and flattens at high V.", "payload": {"question_id": "cuet-phy-dual-debroglie-d01", "subtopic": "de Broglie wavelength vs potential", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "understand", "options": [{"key": "A", "text": "A straight line with negative slope", "is_correct": false}, {"key": "B", "text": "A rectangular hyperbola (λ ∝ 1/√V)", "is_correct": true}, {"key": "C", "text": "A parabola opening upward", "is_correct": false}, {"key": "D", "text": "An exponential decay curve", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A straight line would mean λ ∝ V, but the relation is λ ∝ 1/√V.", "misconception": "Assuming linear relationship"}, {"option_key": "C", "hint": "A parabola would mean λ ∝ V², which increases with V — opposite of what happens.", "misconception": null}, {"option_key": "D", "hint": "Exponential decay (λ ∝ e⁻ᵛ) drops much faster than 1/√V. The curve is algebraic, not exponential.", "misconception": "Confusing power law with exponential"}], "image_uri": "diagrams/cuet-phy-dual-debroglie-d01.png", "image_alt": "Graph showing λ on y-axis vs V on x-axis. Curve is a decreasing hyperbolic shape approaching the x-axis as V increases."}, "image_alt": "Graph showing λ on y-axis vs V on x-axis. Curve is a decreasing hyperbolic shape approaching the x-axis as V increases.", "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "accelerating-potential", "graphical-analysis"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows the Davisson-Germer experiment setup with an electron beam hitting a nickel crystal. The detector is at angle φ from the incident beam. A strong diffraction peak is observed at φ = 50° when the accelerating voltage is 54 V. What is the interplanar spacing d of the crystal if the first-order maximum is observed?", "explanation": "In Davisson-Germer: scattering angle θ = (180° − φ)/2 = (180° − 50°)/2 = 65°. Bragg''s law: nλ = 2d sin θ. For 54V electrons: λ = 1.226/√54 = 0.167 nm. So d = λ/(2 sin 65°) = 0.167/(2 × 0.906) = 0.092 nm ≈ 0.91 Å.", "payload": {"question_id": "cuet-phy-dual-debroglie-d02", "subtopic": "Davisson-Germer experiment analysis", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "0.167 nm", "is_correct": false}, {"key": "B", "text": "0.123 nm", "is_correct": false}, {"key": "C", "text": "0.092 nm", "is_correct": true}, {"key": "D", "text": "0.184 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.167 nm is the de Broglie wavelength itself, not the interplanar spacing.", "misconception": "Confusing wavelength with spacing"}, {"option_key": "B", "hint": "This would result from using φ directly in Bragg''s law instead of converting to θ.", "misconception": null}, {"option_key": "D", "hint": "0.184 nm = λ/sin 65° — missing the factor of 2 in Bragg''s law.", "misconception": "Forgetting the factor 2 in 2d sin θ"}], "image_uri": "diagrams/cuet-phy-dual-debroglie-d02.png", "image_alt": "Davisson-Germer setup: electron gun on left, nickel crystal in center, movable detector showing peak at φ=50°, with scattering angle θ marked"}, "image_alt": "Davisson-Germer setup: electron gun on left, nickel crystal in center, movable detector showing peak at φ=50°, with scattering angle θ marked", "correct_answer": "C", "concept_tags": ["davisson-germer", "electron-diffraction", "bragg-law"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following particles in order of increasing de Broglie wavelength when all have the same kinetic energy:\n(I) Proton\n(II) Electron\n(III) Alpha particle\n(IV) Neutron", "explanation": "λ = h/√(2mKE). At same KE, λ ∝ 1/√m. Masses: electron (9.1×10⁻³¹) < proton ≈ neutron (1.67×10⁻²⁷) < alpha (6.64×10⁻²⁷). Increasing λ means decreasing mass: α < p ≈ n < e. So III → (I,IV) → II.", "payload": {"question_id": "cuet-phy-dual-debroglie-ls01", "subtopic": "Wavelength comparison of particles", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "III → IV → I → II", "is_correct": true}, {"key": "B", "text": "II → I → IV → III", "is_correct": false}, {"key": "C", "text": "I → IV → III → II", "is_correct": false}, {"key": "D", "text": "III → I → IV → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing wavelength. Electron has the largest λ, not smallest.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Proton and neutron have nearly equal mass, and alpha is heavier — so alpha has the smallest λ.", "misconception": null}, {"option_key": "D", "hint": "Proton and neutron have nearly equal mass, so their wavelengths are nearly equal. Neutron (IV) should be close to proton (I).", "misconception": "Ignoring near-equal masses of p and n"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "mass-dependence", "particle-comparison"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-photoelectric", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the variation of stopping potential (V₀) versus frequency (ν) for two different metals P and Q. Both lines are parallel. Which metal has a higher work function?", "explanation": "From Einstein''s equation: eV₀ = hν − φ, so V₀ = (h/e)ν − φ/e. The slope h/e is same for all metals (parallel lines). The x-intercept gives threshold frequency ν₀ = φ/h. Since Q has higher threshold frequency (ν₂ > ν₁), Q has higher work function φ = hν₀.", "payload": {"question_id": "cuet-phy-dual-photo-d01", "subtopic": "Stopping potential vs frequency graph", "topic_name": "Photoelectric Effect and Einstein''s Equation", "bloom_level": "analyze", "options": [{"key": "A", "text": "Metal P", "is_correct": false}, {"key": "B", "text": "Metal Q", "is_correct": true}, {"key": "C", "text": "Both have equal work functions", "is_correct": false}, {"key": "D", "text": "Cannot be determined from the graph", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P has lower threshold frequency, meaning lower work function φ = hν₀.", "misconception": "Confusing lower threshold with higher work function"}, {"option_key": "C", "hint": "The lines have different x-intercepts, so work functions must differ.", "misconception": null}, {"option_key": "D", "hint": "The x-intercept directly gives threshold frequency, from which work function is determined.", "misconception": null}], "image_uri": "diagrams/cuet-phy-dual-photo-d01.png", "image_alt": "V₀ vs ν graph with two parallel straight lines. Line P has threshold frequency ν₁ and line Q has threshold frequency ν₂ where ν₂ > ν₁"}, "image_alt": "V₀ vs ν graph with two parallel straight lines. Line P has threshold frequency ν₁ and line Q has threshold frequency ν₂ where ν₂ > ν₁", "correct_answer": "B", "concept_tags": ["stopping-potential", "work-function", "threshold-frequency"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-photoelectric", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows the I-V characteristics of a photoelectric cell for two different intensities I₁ and I₂ (I₂ > I₁) of light at the same frequency. What remains the same for both curves?", "explanation": "At same frequency, the stopping potential V₀ depends only on frequency (V₀ = hν/e − φ/e), not on intensity. Higher intensity increases the number of photoelectrons (higher saturation current) but doesn''t change their maximum KE. So stopping potential is the same.", "payload": {"question_id": "cuet-phy-dual-photo-d02", "subtopic": "Effect of intensity on photoelectric current", "topic_name": "Photoelectric Effect and Einstein''s Equation", "bloom_level": "understand", "options": [{"key": "A", "text": "The saturation current", "is_correct": false}, {"key": "B", "text": "The photoelectric current at zero voltage", "is_correct": false}, {"key": "C", "text": "The stopping potential", "is_correct": true}, {"key": "D", "text": "Both saturation current and stopping potential", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Saturation current increases with intensity — more photons eject more electrons.", "misconception": "Thinking saturation current is independent of intensity"}, {"option_key": "B", "hint": "Current at zero voltage also depends on the number of electrons emitted, which changes with intensity.", "misconception": null}, {"option_key": "D", "hint": "Saturation current changes with intensity; only stopping potential stays constant.", "misconception": null}], "image_uri": "diagrams/cuet-phy-dual-photo-d02.png", "image_alt": "I-V graph showing two curves: I₂ (higher saturation current) and I₁ (lower saturation current), both reaching the same stopping potential −V₀ on the negative voltage side"}, "image_alt": "I-V graph showing two curves: I₂ (higher saturation current) and I₁ (lower saturation current), both reaching the same stopping potential −V₀ on the negative voltage side", "correct_answer": "C", "concept_tags": ["photoelectric-effect", "intensity", "stopping-potential"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-photoelectric", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following electromagnetic radiations in order of increasing ability to cause photoelectric emission from a metal with work function 2.0 eV:\n(I) Red light (1.8 eV)\n(II) Yellow light (2.1 eV)\n(III) Blue light (2.8 eV)\n(IV) Ultraviolet (4.0 eV)", "explanation": "Only photons with energy > work function (2.0 eV) cause emission. Red (1.8 eV) cannot cause emission at all. For those that can: max KE = hν − φ. Yellow: 0.1 eV, Blue: 0.8 eV, UV: 2.0 eV. Order: I (no emission) → II → III → IV.", "payload": {"question_id": "cuet-phy-dual-photo-ls01", "subtopic": "Energy threshold for photoemission", "topic_name": "Photoelectric Effect and Einstein''s Equation", "bloom_level": "apply", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → III → II → IV", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing ability, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Blue light (2.8 eV) gives more KE than yellow (2.1 eV), so III comes after II.", "misconception": null}, {"option_key": "D", "hint": "Red light (1.8 eV) has less energy than the work function, so it cannot cause emission at all — it should be first (least ability).", "misconception": "Thinking all light causes photoemission"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["photoelectric-effect", "photon-energy", "threshold-energy"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a half-wave rectifier circuit with an AC input of peak voltage 10 V and a silicon diode (barrier potential 0.7 V). What is the peak value of the output voltage across the load resistor?", "explanation": "In a half-wave rectifier, the diode conducts only during the positive half-cycle. The output peak voltage = input peak − barrier potential = 10 − 0.7 = 9.3 V.", "payload": {"question_id": "cuet-phy-semi-diode-d01", "subtopic": "Half-wave rectifier output", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "apply", "options": [{"key": "A", "text": "10 V", "is_correct": false}, {"key": "B", "text": "5 V", "is_correct": false}, {"key": "C", "text": "9.3 V", "is_correct": true}, {"key": "D", "text": "10.7 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 V ignores the voltage drop across the diode (0.7 V for silicon).", "misconception": "Ignoring diode barrier potential"}, {"option_key": "B", "hint": "5 V would be the average, not the peak of the output.", "misconception": "Confusing peak with average value"}, {"option_key": "D", "hint": "The diode drops voltage, not adds — output is always less than input peak.", "misconception": "Adding barrier potential instead of subtracting"}], "image_uri": "diagrams/cuet-phy-semi-diode-d01.png", "image_alt": "Half-wave rectifier circuit: AC source connected to diode (D) in series with load resistor (R_L). Output shows positive half-cycles only."}, "image_alt": "Half-wave rectifier circuit: AC source connected to diode (D) in series with load resistor (R_L). Output shows positive half-cycles only.", "correct_answer": "C", "concept_tags": ["half-wave-rectifier", "diode-barrier", "peak-voltage"]}]'::jsonb, 'correction-batch-2');

-- correction-batch-2 questions 8-14
SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a Zener diode voltage regulator circuit. The Zener breakdown voltage is 6 V and the input voltage varies from 9 V to 15 V. What is the output voltage across the load?", "explanation": "In a Zener voltage regulator, when the input exceeds the Zener voltage, the Zener diode maintains a constant voltage across itself (and the load). So output = Zener voltage = 6 V, regardless of input variation from 9 V to 15 V.", "payload": {"question_id": "cuet-phy-semi-diode-d02", "subtopic": "Zener voltage regulation", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "6 V (constant)", "is_correct": true}, {"key": "B", "text": "Varies from 9 V to 15 V", "is_correct": false}, {"key": "C", "text": "Varies from 3 V to 9 V", "is_correct": false}, {"key": "D", "text": "12 V (average of input range)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would mean no regulation — the whole point of the Zener is to keep output constant.", "misconception": "Not understanding voltage regulation"}, {"option_key": "C", "hint": "The excess voltage (input − Zener) drops across Rs, not across the load.", "misconception": "Subtracting Zener voltage from input"}, {"option_key": "D", "hint": "The Zener maintains exactly its breakdown voltage, not the average.", "misconception": null}], "image_uri": "diagrams/cuet-phy-semi-diode-d02.png", "image_alt": "Zener regulator circuit: input voltage source, series resistor Rs, Zener diode in reverse bias across load resistor R_L, output = 6V"}, "image_alt": "Zener regulator circuit: input voltage source, series resistor Rs, Zener diode in reverse bias across load resistor R_L, output = 6V", "correct_answer": "A", "concept_tags": ["zener-diode", "voltage-regulator", "breakdown-voltage"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following special-purpose diodes in order of increasing wavelength of radiation they typically interact with:\n(I) Solar cell\n(II) LED (red)\n(III) Photodiode (IR)\n(IV) X-ray detector diode", "explanation": "X-ray: ~0.01–10 nm, Solar cell: visible ~400–700 nm, LED (red): ~620–750 nm, IR photodiode: ~800–1600 nm. Order of increasing wavelength: IV → I → II → III.", "payload": {"question_id": "cuet-phy-semi-diode-ls01", "subtopic": "Spectral range of different diodes", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "III → II → I → IV", "is_correct": false}, {"key": "B", "text": "IV → I → II → III", "is_correct": true}, {"key": "C", "text": "IV → II → I → III", "is_correct": false}, {"key": "D", "text": "I → II → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is roughly the reverse order. X-rays have the shortest wavelength.", "misconception": "Reversing wavelength order"}, {"option_key": "C", "hint": "Solar cells absorb visible light (~500 nm avg), red LEDs emit ~650 nm — solar cell range starts at shorter wavelength.", "misconception": null}, {"option_key": "D", "hint": "Solar cells work in visible range, not the shortest wavelength.", "misconception": null}]}, "image_alt": null, "correct_answer": "B", "concept_tags": ["special-diodes", "wavelength", "electromagnetic-spectrum"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-pn", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the I-V characteristic of a p-n junction diode. In forward bias, the diode starts conducting significantly at voltage Vk (knee voltage). If Vk = 0.7 V and the forward resistance above Vk is 20 Ω, what current flows when 1.5 V is applied?", "explanation": "Above knee voltage, I = (V − Vk)/Rf = (1.5 − 0.7)/20 = 0.8/20 = 0.04 A = 40 mA.", "payload": {"question_id": "cuet-phy-semi-pn-d01", "subtopic": "Forward bias I-V characteristics", "topic_name": "p-n Junction Diode and Characteristics", "bloom_level": "apply", "options": [{"key": "A", "text": "75 mA", "is_correct": false}, {"key": "B", "text": "40 mA", "is_correct": true}, {"key": "C", "text": "35 mA", "is_correct": false}, {"key": "D", "text": "0 mA", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "75 mA = 1.5V/20Ω — this ignores the knee voltage drop of 0.7 V.", "misconception": "Ignoring knee voltage in calculation"}, {"option_key": "C", "hint": "35 mA = 0.7/20 — this uses the knee voltage instead of (V − Vk).", "misconception": "Using Vk instead of (V − Vk)"}, {"option_key": "D", "hint": "1.5 V > 0.7 V (knee voltage), so the diode is conducting.", "misconception": "Thinking diode doesn''t conduct at 1.5V"}], "image_uri": "diagrams/cuet-phy-semi-pn-d01.png", "image_alt": "I-V curve of p-n junction: negligible current below Vk=0.7V in forward bias, then steeply rising current. Reverse bias shows very small constant current until breakdown."}, "image_alt": "I-V curve of p-n junction: negligible current below Vk=0.7V in forward bias, then steeply rising current. Reverse bias shows very small constant current until breakdown.", "correct_answer": "B", "concept_tags": ["pn-junction", "IV-characteristics", "knee-voltage", "forward-bias"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-pn", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows the energy band diagram of a p-n junction at equilibrium (no external bias). The built-in potential barrier is shown. What happens to the width of the depletion region when forward bias is applied?", "explanation": "Forward bias reduces the potential barrier, allowing majority carriers to cross. This reduces the depletion region width. The external voltage opposes the built-in potential, narrowing the space charge region.", "payload": {"question_id": "cuet-phy-semi-pn-d02", "subtopic": "Effect of bias on depletion region", "topic_name": "p-n Junction Diode and Characteristics", "bloom_level": "understand", "options": [{"key": "A", "text": "Decreases", "is_correct": true}, {"key": "B", "text": "Increases", "is_correct": false}, {"key": "C", "text": "Remains the same", "is_correct": false}, {"key": "D", "text": "First increases then decreases", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Increase in depletion width occurs in reverse bias, not forward bias.", "misconception": "Confusing forward and reverse bias effects"}, {"option_key": "C", "hint": "Any applied bias changes the equilibrium — depletion width must change.", "misconception": null}, {"option_key": "D", "hint": "Forward bias consistently reduces the barrier — there''s no reversal.", "misconception": null}], "image_uri": "diagrams/cuet-phy-semi-pn-d02.png", "image_alt": "Energy band diagram of p-n junction showing conduction band, valence band, Fermi level, depletion region width W, and built-in potential Vbi"}, "image_alt": "Energy band diagram of p-n junction showing conduction band, valence band, Fermi level, depletion region width W, and built-in potential Vbi", "correct_answer": "A", "concept_tags": ["depletion-region", "forward-bias", "energy-band-diagram"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-pn", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the formation of a p-n junction in the correct order:\n(I) Diffusion of majority carriers across the junction\n(II) Formation of immobile ion layer (depletion region)\n(III) Establishment of built-in electric field\n(IV) Equilibrium — diffusion current equals drift current", "explanation": "When p and n types are joined: majority carriers diffuse (I), leaving behind immobile ions that form the depletion region (II), creating a built-in electric field (III), which opposes further diffusion until equilibrium is reached (IV).", "payload": {"question_id": "cuet-phy-semi-pn-ls01", "subtopic": "Formation of p-n junction", "topic_name": "p-n Junction Diode and Characteristics", "bloom_level": "understand", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "III → I → II → IV", "is_correct": false}, {"key": "C", "text": "II → I → III → IV", "is_correct": false}, {"key": "D", "text": "I → III → II → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The electric field forms because of the depletion region, not before diffusion.", "misconception": "Thinking field exists before junction formation"}, {"option_key": "C", "hint": "Depletion region forms because of diffusion — diffusion must happen first.", "misconception": null}, {"option_key": "D", "hint": "The immobile ions (depletion region) form first, then the field arises from them.", "misconception": "Reversing depletion region and field formation"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["pn-junction-formation", "depletion-region", "equilibrium"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-transistor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the output characteristics (Ic vs Vce) of an NPN transistor in common-emitter configuration for two base currents Ib1 and Ib2 (Ib2 > Ib1). If Ib1 = 20 μA gives Ic = 2 mA, what is the current gain β?", "explanation": "Current gain β = Ic/Ib = 2 mA / 20 μA = 2×10⁻³ / 20×10⁻⁶ = 100.", "payload": {"question_id": "cuet-phy-semi-transistor-d01", "subtopic": "Transistor current gain", "topic_name": "Transistor, Logic Gates, and Amplifiers", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "50", "is_correct": false}, {"key": "C", "text": "200", "is_correct": false}, {"key": "D", "text": "100", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "β = 10 would mean Ic = 10 × 20μA = 0.2 mA, not 2 mA.", "misconception": "Unit conversion error"}, {"option_key": "B", "hint": "β = 50 would mean Ic = 50 × 20μA = 1 mA, not 2 mA.", "misconception": null}, {"option_key": "C", "hint": "β = 200 would mean Ic = 200 × 20μA = 4 mA, not 2 mA.", "misconception": null}], "image_uri": "diagrams/cuet-phy-semi-transistor-d01.png", "image_alt": "Ic vs Vce graph with two curves: Ib2 (upper) and Ib1 (lower). Curves show saturation region, active region (nearly flat), and labelled Ib values."}, "image_alt": "Ic vs Vce graph with two curves: Ib2 (upper) and Ib1 (lower). Curves show saturation region, active region (nearly flat), and labelled Ib values.", "correct_answer": "D", "concept_tags": ["transistor", "current-gain", "common-emitter"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-logic-gates", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a two-input NAND gate. What is the output Y when both inputs A = 1 and B = 1?", "explanation": "NAND gate: Y = NOT(A AND B). When A=1, B=1: A AND B = 1, so Y = NOT(1) = 0. NAND gives 0 only when both inputs are 1.", "payload": {"question_id": "cuet-phy-semi-transistor-d02", "subtopic": "NAND gate truth table", "topic_name": "Transistor, Logic Gates, and Amplifiers", "bloom_level": "remember", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "0", "is_correct": true}, {"key": "C", "text": "Undefined", "is_correct": false}, {"key": "D", "text": "Toggles between 0 and 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 would be the output of an AND gate, not NAND. NAND is the complement of AND.", "misconception": "Confusing AND with NAND"}, {"option_key": "C", "hint": "Logic gates always have a defined output for given inputs.", "misconception": null}, {"option_key": "D", "hint": "With fixed inputs, the output is fixed — no toggling.", "misconception": null}], "image_uri": "diagrams/cuet-phy-semi-transistor-d02.png", "image_alt": "NAND gate symbol with inputs A and B, output Y. Truth table partially shown."}, "image_alt": "NAND gate symbol with inputs A and B, output Y. Truth table partially shown.", "correct_answer": "B", "concept_tags": ["logic-gates", "NAND-gate", "boolean-algebra"]}]'::jsonb, 'correction-batch-2');

