SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-transistor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following transistor operating regions in order of increasing collector current for a given base current:\n(I) Cut-off region\n(II) Active region\n(III) Saturation region", "explanation": "In cut-off: both junctions reverse biased, Ic ≈ 0. In active: base-emitter forward, collector-base reverse, Ic = βIb (moderate). In saturation: both forward biased, Ic reaches maximum. Order: cut-off < active < saturation.", "payload": {"question_id": "cuet-phy-semi-transistor-ls01", "subtopic": "Transistor operating regions", "topic_name": "Transistor, Logic Gates, and Amplifiers", "bloom_level": "understand", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is decreasing order. Cut-off has minimum Ic.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Cut-off has essentially zero Ic — it cannot be between active and saturation.", "misconception": null}, {"option_key": "D", "hint": "In active region, Ic = βIb. In saturation, Ic is at maximum. Active comes before saturation.", "misconception": "Confusing active and saturation regions"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["transistor-regions", "cut-off", "active", "saturation"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a parallel plate capacitor with plate area A and separation d. If the separation is doubled while keeping the charge constant, what happens to the energy stored?", "explanation": "At constant charge Q: U = Q²/(2C) = Q²d/(2ε₀A). If d → 2d, then U → 2U. Energy doubles because work is done against the attractive force to pull the plates apart.", "payload": {"question_id": "cuet-phy-pot-cap-d01", "subtopic": "Energy in a capacitor", "topic_name": "Capacitors and Capacitance", "bloom_level": "apply", "options": [{"key": "A", "text": "Halved", "is_correct": false}, {"key": "B", "text": "Remains the same", "is_correct": false}, {"key": "C", "text": "Doubled", "is_correct": true}, {"key": "D", "text": "Quadrupled", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Energy halves if V is constant (U = CV²/2, C halves). But here charge is constant.", "misconception": "Confusing constant charge with constant voltage"}, {"option_key": "B", "hint": "Changing plate separation changes capacitance, which changes stored energy.", "misconception": null}, {"option_key": "D", "hint": "U ∝ d (at constant Q), so doubling d doubles U, not quadruples.", "misconception": "Using d² instead of d"}], "image_uri": "diagrams/cuet-phy-pot-cap-d01.png", "image_alt": "Two parallel plates with charges +Q and −Q, separation d, electric field E between them. Arrow showing d increasing to 2d."}, "image_alt": "Two parallel plates with charges +Q and −Q, separation d, electric field E between them. Arrow showing d increasing to 2d.", "correct_answer": "C", "concept_tags": ["parallel-plate-capacitor", "energy-stored", "charge-constant"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a capacitor being charged through a resistor. The graph shows the voltage across the capacitor vs time. What is the voltage at time t = RC (one time constant)?", "explanation": "During charging: V(t) = V₀(1 − e⁻ᵗ/ᴿᶜ). At t = RC: V = V₀(1 − e⁻¹) = V₀(1 − 0.368) = 0.632V₀ ≈ 63.2% of maximum voltage.", "payload": {"question_id": "cuet-phy-pot-cap-d02", "subtopic": "RC charging circuit", "topic_name": "Capacitors and Capacitance", "bloom_level": "remember", "options": [{"key": "A", "text": "50% of V₀", "is_correct": false}, {"key": "B", "text": "63.2% of V₀", "is_correct": true}, {"key": "C", "text": "37% of V₀", "is_correct": false}, {"key": "D", "text": "100% of V₀", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "50% is reached at t = 0.693RC (= RC × ln2), not at t = RC.", "misconception": "Confusing half-life with time constant"}, {"option_key": "C", "hint": "37% = e⁻¹ is the fraction remaining to charge, not the fraction charged.", "misconception": "Using e⁻¹ instead of (1−e⁻¹)"}, {"option_key": "D", "hint": "100% is only reached at t → ∞. The capacitor charges asymptotically.", "misconception": null}], "image_uri": "diagrams/cuet-phy-pot-cap-d02.png", "image_alt": "RC charging curve: voltage rises exponentially from 0 toward V₀. Time constant τ=RC marked on x-axis. Voltage at τ marked with dashed lines."}, "image_alt": "RC charging curve: voltage rises exponentially from 0 toward V₀. Time constant τ=RC marked on x-axis. Voltage at τ marked with dashed lines.", "correct_answer": "B", "concept_tags": ["RC-circuit", "time-constant", "charging-curve"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following capacitor configurations in order of increasing equivalent capacitance, given three identical capacitors each of capacitance C:\n(I) All three in series\n(II) All three in parallel\n(III) Two in series, combination in parallel with the third", "explanation": "Series: 1/Ceq = 1/C + 1/C + 1/C → Ceq = C/3. Two series + parallel: Ceq = C/2 + C = 3C/2. All parallel: Ceq = 3C. Order: C/3 < 3C/2 < 3C → I → III → II.", "payload": {"question_id": "cuet-phy-pot-cap-ls01", "subtopic": "Capacitor combinations", "topic_name": "Capacitors and Capacitance", "bloom_level": "apply", "options": [{"key": "A", "text": "I → III → II", "is_correct": true}, {"key": "B", "text": "II → III → I", "is_correct": false}, {"key": "C", "text": "I → II → III", "is_correct": false}, {"key": "D", "text": "III → I → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing capacitance.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "All parallel (3C) > two-series-plus-one-parallel (3C/2).", "misconception": "Thinking all parallel gives less than mixed"}, {"option_key": "D", "hint": "All series (C/3) gives the smallest capacitance, not the mixed configuration.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["capacitor-combinations", "series-parallel", "equivalent-capacitance"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dielectric", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a parallel plate capacitor with a dielectric slab of dielectric constant K = 3 inserted to fill half the space between the plates (half the thickness). If the original capacitance is C₀, what is the new capacitance?", "explanation": "This is equivalent to two capacitors in series: C₁ = Kε₀A/(d/2) = 2Kε₀A/d = 2KC₀ and C₂ = ε₀A/(d/2) = 2ε₀A/d = 2C₀. In series: 1/C = 1/(2KC₀) + 1/(2C₀) = (1+K)/(2KC₀). So C = 2KC₀/(1+K) = 2(3)C₀/(1+3) = 6C₀/4 = 1.5C₀.", "payload": {"question_id": "cuet-phy-pot-dielec-d01", "subtopic": "Capacitor with partial dielectric", "topic_name": "Combination of Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "3C₀", "is_correct": false}, {"key": "B", "text": "2C₀", "is_correct": false}, {"key": "C", "text": "1.5C₀", "is_correct": true}, {"key": "D", "text": "C₀/3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3C₀ would be the capacitance if the entire gap were filled with dielectric.", "misconception": "Treating half-filled as fully filled"}, {"option_key": "B", "hint": "2C₀ would result from an incorrect series combination formula.", "misconception": null}, {"option_key": "D", "hint": "C₀/3 would mean capacitance decreased, but adding dielectric always increases capacitance.", "misconception": "Dividing by K instead of using series formula"}], "image_uri": "diagrams/cuet-phy-pot-dielec-d01.png", "image_alt": "Parallel plate capacitor with total separation d. Bottom half (d/2) filled with dielectric K=3, top half (d/2) is air. Equivalent to two capacitors in series."}, "image_alt": "Parallel plate capacitor with total separation d. Bottom half (d/2) filled with dielectric K=3, top half (d/2) is air. Equivalent to two capacitors in series.", "correct_answer": "C", "concept_tags": ["dielectric", "capacitance", "series-combination"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dielectric", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The circuit shows three capacitors: C₁ = 2μF, C₂ = 3μF in series, and this combination in parallel with C₃ = 4μF, connected to a 10V battery. What is the charge on C₃?", "explanation": "C₃ is directly across the battery (parallel branch), so V across C₃ = 10 V. Charge on C₃ = C₃ × V = 4μF × 10V = 40 μC.", "payload": {"question_id": "cuet-phy-pot-dielec-d02", "subtopic": "Charge in capacitor circuits", "topic_name": "Combination of Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "12 μC", "is_correct": false}, {"key": "B", "text": "24 μC", "is_correct": false}, {"key": "C", "text": "30 μC", "is_correct": false}, {"key": "D", "text": "40 μC", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "12 μC = series combination charge (C_series × 10V = 1.2μF × 10V). That''s for the series branch, not C₃.", "misconception": "Calculating charge on wrong branch"}, {"option_key": "B", "hint": "24 μC comes from using wrong capacitance value.", "misconception": null}, {"option_key": "C", "hint": "30 μC = 3μF × 10V — using C₂ instead of C₃.", "misconception": "Confusing which capacitor is in parallel"}], "image_uri": "diagrams/cuet-phy-pot-dielec-d02.png", "image_alt": "Circuit: C1=2μF and C2=3μF in series, their combination in parallel with C3=4μF, across 10V battery."}, "image_alt": "Circuit: C1=2μF and C2=3μF in series, their combination in parallel with C3=4μF, across 10V battery.", "correct_answer": "D", "concept_tags": ["capacitor-circuit", "charge", "parallel-combination"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dielectric", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following materials in order of increasing dielectric constant:\n(I) Vacuum\n(II) Air\n(III) Paper\n(IV) Water", "explanation": "Dielectric constants: Vacuum = 1 (exact), Air ≈ 1.0006, Paper ≈ 3.7, Water ≈ 80. Order: I → II → III → IV.", "payload": {"question_id": "cuet-phy-pot-dielec-ls01", "subtopic": "Dielectric constants of materials", "topic_name": "Combination of Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → II → IV → III", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing dielectric constant.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Water has a very high dielectric constant (~80) — much higher than paper (~3.7).", "misconception": "Underestimating water''s dielectric constant"}, {"option_key": "D", "hint": "Vacuum has the lowest possible dielectric constant (exactly 1), lower than air.", "misconception": "Thinking air has lower K than vacuum"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["dielectric-constant", "materials", "permittivity"]}]'::jsonb, 'correction-batch-2');

