SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows equipotential surfaces around a positive point charge. The surfaces are concentric spheres at potentials 60V, 30V, and 20V. What is the ratio of radii r₁:r₂:r₃ of these surfaces?", "explanation": "For a point charge: V = kQ/r, so r = kQ/V. r₁ = kQ/60, r₂ = kQ/30, r₃ = kQ/20. Ratio r₁:r₂:r₃ = 1/60 : 1/30 : 1/20 = 1:2:3.", "payload": {"question_id": "cuet-phy-pot-potential-d01", "subtopic": "Equipotential surfaces", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "3 : 2 : 1", "is_correct": false}, {"key": "B", "text": "1 : 2 : 3", "is_correct": true}, {"key": "C", "text": "1 : 1 : 1", "is_correct": false}, {"key": "D", "text": "6 : 3 : 2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3:2:1 would mean higher potential at larger radius, but V decreases with r for a positive charge.", "misconception": "Thinking V ∝ r instead of V ∝ 1/r"}, {"option_key": "C", "hint": "Equal radii would mean equal potentials on all surfaces.", "misconception": null}, {"option_key": "D", "hint": "6:3:2 = V₁:V₂:V₃ ratio, but radius is inversely proportional to V.", "misconception": "Using V ratio instead of 1/V ratio"}], "image_uri": "diagrams/cuet-phy-pot-potential-d01.png", "image_alt": "Three concentric circles (equipotential surfaces) around a positive charge. Inner circle: 60V, middle: 30V, outer: 20V"}, "image_alt": "Three concentric circles (equipotential surfaces) around a positive charge. Inner circle: 60V, middle: 30V, outer: 20V", "correct_answer": "B", "concept_tags": ["equipotential-surfaces", "point-charge", "electric-potential"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The graph shows the variation of electric potential (V) along the x-axis due to two equal positive charges placed at x = −a and x = +a. What is the potential at the midpoint (x = 0)?", "explanation": "At midpoint x = 0, distance from each charge is a. V = kQ/a + kQ/a = 2kQ/a. The potential is maximum along the line if we only consider the midpoint between the charges — it''s actually a saddle point (minimum along x but maximum in perpendicular directions). But V at x=0 is simply 2kQ/a, which is positive and non-zero.", "payload": {"question_id": "cuet-phy-pot-potential-d02", "subtopic": "Potential due to charge system", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "kQ/a", "is_correct": false}, {"key": "C", "text": "2kQ/a", "is_correct": true}, {"key": "D", "text": "kQ/2a", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The electric FIELD is zero at the midpoint (by symmetry), but potential is a scalar and adds up, not cancels.", "misconception": "Confusing zero field with zero potential"}, {"option_key": "B", "hint": "kQ/a is the contribution from one charge only. Both charges contribute equally.", "misconception": "Counting only one charge"}, {"option_key": "D", "hint": "kQ/2a would mean the distance from each charge is 2a, but it''s only a.", "misconception": "Using wrong distance"}], "image_uri": "diagrams/cuet-phy-pot-potential-d02.png", "image_alt": "V vs x graph showing two peaks at x=−a and x=+a (locations of charges), with a local minimum at x=0 that is still positive. Potential approaches zero far from charges."}, "image_alt": "V vs x graph showing two peaks at x=−a and x=+a (locations of charges), with a local minimum at x=0 that is still positive. Potential approaches zero far from charges.", "correct_answer": "C", "concept_tags": ["superposition", "electric-potential", "two-charges"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following quantities in order of increasing value for a positive point charge Q at distances r, 2r, and 3r:\n(I) Potential at 3r\n(II) Potential at r\n(III) Potential at 2r", "explanation": "V = kQ/r, so V(r) = kQ/r, V(2r) = kQ/2r, V(3r) = kQ/3r. Increasing order: V(3r) < V(2r) < V(r), i.e., I → III → II.", "payload": {"question_id": "cuet-phy-pot-potential-ls01", "subtopic": "Potential variation with distance", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "I → III → II", "is_correct": true}, {"key": "B", "text": "II → III → I", "is_correct": false}, {"key": "C", "text": "I → II → III", "is_correct": false}, {"key": "D", "text": "III → I → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing potential.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "V at r is the highest (closest to charge), so II should be last.", "misconception": "Thinking closer means lower potential"}, {"option_key": "D", "hint": "V at 2r is between V at r and V at 3r.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["electric-potential", "distance-dependence", "point-charge"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The phasor diagram shows the voltage across resistor (VR), inductor (VL), and capacitor (VC) in a series LCR circuit. VL > VC. What is the phase relationship between the source voltage and current?", "explanation": "When VL > VC, the net reactive voltage (VL − VC) is positive (inductive). The resultant voltage V leads VR (which is in phase with current) by angle φ = tan⁻¹((VL−VC)/VR). So voltage leads current — the circuit is inductive.", "payload": {"question_id": "cuet-phy-ac-circuits-d01", "subtopic": "Phasor diagram of LCR circuit", "topic_name": "AC Circuits (R, L, C, LCR Series)", "bloom_level": "analyze", "options": [{"key": "A", "text": "Voltage lags current", "is_correct": false}, {"key": "B", "text": "Voltage leads current", "is_correct": true}, {"key": "C", "text": "Voltage and current are in phase", "is_correct": false}, {"key": "D", "text": "Voltage and current are 90° out of phase", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Voltage lags current when VC > VL (capacitive circuit), but here VL > VC.", "misconception": "Confusing inductive and capacitive behavior"}, {"option_key": "C", "hint": "In-phase occurs only at resonance (VL = VC), but here VL ≠ VC.", "misconception": "Assuming resonance condition"}, {"option_key": "D", "hint": "90° phase occurs in purely inductive or capacitive circuits, not in LCR with resistance.", "misconception": null}], "image_uri": "diagrams/cuet-phy-ac-circuits-d01.png", "image_alt": "Phasor diagram: VR along x-axis (horizontal), VL pointing up, VC pointing down. VL > VC. Resultant voltage V at angle φ above VR."}, "image_alt": "Phasor diagram: VR along x-axis (horizontal), VL pointing up, VC pointing down. VL > VC. Resultant voltage V at angle φ above VR.", "correct_answer": "B", "concept_tags": ["phasor-diagram", "LCR-circuit", "phase-angle"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The graph shows the variation of impedance (Z) with frequency (f) for a series LCR circuit. At what frequency is the impedance minimum?", "explanation": "In a series LCR circuit, Z = √(R² + (XL−XC)²). Z is minimum when XL = XC (resonance), giving Z_min = R. This occurs at resonant frequency f₀ = 1/(2π√LC).", "payload": {"question_id": "cuet-phy-ac-circuits-d02", "subtopic": "Impedance vs frequency", "topic_name": "AC Circuits (R, L, C, LCR Series)", "bloom_level": "understand", "options": [{"key": "A", "text": "At resonant frequency f₀ = 1/(2π√LC)", "is_correct": true}, {"key": "B", "text": "At f = 0 (DC)", "is_correct": false}, {"key": "C", "text": "At very high frequency", "is_correct": false}, {"key": "D", "text": "At f = R/(2πL)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "At f = 0, XC = 1/(2πfC) → ∞, so Z → ∞. This is maximum, not minimum.", "misconception": "Thinking DC gives minimum impedance"}, {"option_key": "C", "hint": "At high f, XL = 2πfL → ∞, so Z → ∞ again.", "misconception": null}, {"option_key": "D", "hint": "R/(2πL) is related to the time constant of RL circuit, not resonance of LCR.", "misconception": "Confusing RL time constant with LCR resonance"}], "image_uri": "diagrams/cuet-phy-ac-circuits-d02.png", "image_alt": "Z vs f graph showing a V-shaped curve with minimum at resonant frequency f₀. Z decreases before f₀ and increases after f₀. Minimum Z = R."}, "image_alt": "Z vs f graph showing a V-shaped curve with minimum at resonant frequency f₀. Z decreases before f₀ and increases after f₀. Minimum Z = R.", "correct_answer": "A", "concept_tags": ["impedance", "resonance", "resonant-frequency"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following AC circuit elements in order of increasing phase difference between voltage across the element and current through it:\n(I) Pure resistor\n(II) Pure inductor\n(III) Pure capacitor\n(IV) Series LCR at resonance", "explanation": "Pure resistor: φ = 0°. LCR at resonance: φ = 0° (XL = XC cancel). Pure capacitor: φ = 90° (V lags I). Pure inductor: φ = 90° (V leads I). Taking magnitude: 0° = 0° < 90° = 90°. So (I,IV) < (II,III). All with 0° first, then 90°.", "payload": {"question_id": "cuet-phy-ac-circuits-ls01", "subtopic": "Phase relationships in AC circuits", "topic_name": "AC Circuits (R, L, C, LCR Series)", "bloom_level": "understand", "options": [{"key": "A", "text": "III → I → IV → II", "is_correct": false}, {"key": "B", "text": "II → III → I → IV", "is_correct": false}, {"key": "C", "text": "I = IV → II = III (0°, 0°, 90°, 90°)", "is_correct": true}, {"key": "D", "text": "I → IV → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Capacitor and inductor both have 90° phase difference, same magnitude.", "misconception": null}, {"option_key": "B", "hint": "Resistor and LCR at resonance both have 0° phase difference.", "misconception": "Thinking resonance has non-zero phase"}, {"option_key": "D", "hint": "LCR at resonance behaves like a pure resistor (φ = 0°), same as I.", "misconception": null}]}, "image_alt": null, "correct_answer": "C", "concept_tags": ["phase-difference", "AC-elements", "resonance"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-transformer", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a step-up transformer with primary coil having 100 turns and secondary coil having 500 turns. If the input voltage is 220 V, what is the output voltage?", "explanation": "For an ideal transformer: Vs/Vp = Ns/Np. So Vs = Vp × Ns/Np = 220 × 500/100 = 220 × 5 = 1100 V.", "payload": {"question_id": "cuet-phy-ac-transform-d01", "subtopic": "Transformer turns ratio", "topic_name": "Resonance, Power Factor, and Transformers", "bloom_level": "apply", "options": [{"key": "A", "text": "44 V", "is_correct": false}, {"key": "B", "text": "220 V", "is_correct": false}, {"key": "C", "text": "550 V", "is_correct": false}, {"key": "D", "text": "1100 V", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "44 V = 220/5 — you divided instead of multiplied. This would be the step-down result.", "misconception": "Inverting the turns ratio"}, {"option_key": "B", "hint": "220 V would mean no transformation — the turns ratio is 5:1, not 1:1.", "misconception": null}, {"option_key": "C", "hint": "550 V = 220 × 500/200 — check the denominator, it''s 100, not 200.", "misconception": "Arithmetic error in turns ratio"}], "image_uri": "diagrams/cuet-phy-ac-transform-d01.png", "image_alt": "Transformer with iron core, primary coil (Np=100 turns, 220V input) on left, secondary coil (Ns=500 turns, V=?) on right"}, "image_alt": "Transformer with iron core, primary coil (Np=100 turns, 220V input) on left, secondary coil (Ns=500 turns, V=?) on right", "correct_answer": "D", "concept_tags": ["transformer", "turns-ratio", "step-up"]}]'::jsonb, 'correction-batch-2');

-- correction-batch-2 questions 29-30
SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-transformer", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The graph shows the variation of current (I) with frequency (f) in a series LCR circuit near resonance. The resonant frequency is f₀ = 500 Hz and the half-power frequencies are f₁ = 490 Hz and f₂ = 510 Hz. What is the quality factor Q of the circuit?", "explanation": "Quality factor Q = f₀/Δf = f₀/(f₂ − f₁) = 500/(510 − 490) = 500/20 = 25. Higher Q means sharper resonance peak.", "payload": {"question_id": "cuet-phy-ac-transform-d02", "subtopic": "Quality factor of LCR circuit", "topic_name": "Resonance, Power Factor, and Transformers", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "50", "is_correct": false}, {"key": "C", "text": "25", "is_correct": true}, {"key": "D", "text": "500", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q = 10 would mean bandwidth = 50 Hz, but here it''s only 20 Hz.", "misconception": null}, {"option_key": "B", "hint": "Q = 50 would mean bandwidth = 10 Hz. The bandwidth is f₂ − f₁ = 20 Hz.", "misconception": "Using wrong bandwidth calculation"}, {"option_key": "D", "hint": "500 is the resonant frequency itself, not the quality factor.", "misconception": "Confusing f₀ with Q"}], "image_uri": "diagrams/cuet-phy-ac-transform-d02.png", "image_alt": "I vs f resonance curve: sharp peak at f₀=500Hz. Half-power points at f₁=490Hz and f₂=510Hz where I = Imax/√2. Bandwidth Δf = 20Hz."}, "image_alt": "I vs f resonance curve: sharp peak at f₀=500Hz. Half-power points at f₁=490Hz and f₂=510Hz where I = Imax/√2. Bandwidth Δf = 20Hz.", "correct_answer": "C", "concept_tags": ["quality-factor", "resonance", "bandwidth"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-transformer", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in long-distance power transmission in the correct order:\n(I) Step-down transformer at city substation\n(II) Power generation at power plant\n(III) Step-up transformer at power plant\n(IV) High-voltage transmission through power lines", "explanation": "Power is generated (II), stepped up to high voltage for efficient transmission (III), sent through power lines (IV), then stepped down for consumer use (I).", "payload": {"question_id": "cuet-phy-ac-transform-ls01", "subtopic": "Power transmission system", "topic_name": "Resonance, Power Factor, and Transformers", "bloom_level": "remember", "options": [{"key": "A", "text": "II → IV → III → I", "is_correct": false}, {"key": "B", "text": "II → III → IV → I", "is_correct": true}, {"key": "C", "text": "III → II → IV → I", "is_correct": false}, {"key": "D", "text": "II → III → I → IV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You must step-up before transmitting — sending low voltage over long lines wastes energy as heat (I²R losses).", "misconception": "Skipping the step-up transformer"}, {"option_key": "C", "hint": "Power must be generated before it can be transformed.", "misconception": null}, {"option_key": "D", "hint": "Step-down happens at the receiving end, not before transmission.", "misconception": "Reversing step-down and transmission order"}]}, "image_alt": null, "correct_answer": "B", "concept_tags": ["power-transmission", "transformer", "efficiency"]}]'::jsonb, 'correction-batch-2');

