SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the variation of induced EMF with time when a bar magnet is dropped through a coil. Two peaks are observed — one positive and one negative. What does the second (negative) peak indicate?", "explanation": "As the magnet enters the coil, the increasing flux induces a positive EMF. As it exits, the flux decreases in the opposite sense, inducing a negative EMF. The second peak is larger because the magnet accelerates under gravity.", "payload": {"question_id": "cuet-phy-emi-faraday-d01", "subtopic": "EMF due to changing flux", "topic_name": "Faraday''s Law and Lenz''s Law", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnet has stopped inside the coil", "is_correct": false}, {"key": "B", "text": "The magnet is exiting the coil, reversing the flux change direction", "is_correct": true}, {"key": "C", "text": "The coil resistance has changed", "is_correct": false}, {"key": "D", "text": "The magnet has reversed its polarity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If the magnet stopped, the flux would be constant and EMF would be zero, not negative.", "misconception": "Thinking stationary magnet produces EMF"}, {"option_key": "C", "hint": "Coil resistance doesn''t change during the experiment and doesn''t cause polarity reversal.", "misconception": null}, {"option_key": "D", "hint": "A permanent magnet cannot reverse its polarity spontaneously.", "misconception": null}], "image_uri": "diagrams/cuet-phy-emi-faraday-d01.png", "image_alt": "EMF vs time graph showing positive peak as magnet enters coil, zero briefly, then negative peak as magnet exits"}, "image_alt": "EMF vs time graph showing positive peak as magnet enters coil, zero briefly, then negative peak as magnet exits", "correct_answer": "B", "concept_tags": ["faraday-law", "lenz-law", "induced-emf"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows a rectangular loop of width l moving with velocity v into a region of uniform magnetic field B (perpendicular, into the page). What is the induced EMF when the loop is partially inside the field region?", "explanation": "When the loop is partially inside, only the leading edge (length l) cuts field lines. The motional EMF = Blv. The trailing edge is still outside the field, so it contributes nothing.", "payload": {"question_id": "cuet-phy-emi-faraday-d02", "subtopic": "Motional EMF in changing flux region", "topic_name": "Faraday''s Law and Lenz''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "2Blv", "is_correct": false}, {"key": "C", "text": "Blv", "is_correct": true}, {"key": "D", "text": "Blv/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "EMF is zero only when the entire loop is inside the field (flux not changing).", "misconception": "Thinking EMF is zero when partially inside"}, {"option_key": "B", "hint": "2Blv would occur if both edges were crossing field boundaries, but only one edge is.", "misconception": "Counting both edges"}, {"option_key": "D", "hint": "There is no factor of 1/2 in motional EMF = Blv.", "misconception": null}], "image_uri": "diagrams/cuet-phy-emi-faraday-d02.png", "image_alt": "Rectangular loop of width l moving with velocity v entering a region of uniform B field (into page). Only right side crosses boundary."}, "image_alt": "Rectangular loop of width l moving with velocity v entering a region of uniform B field (into page). Only right side crosses boundary.", "correct_answer": "C", "concept_tags": ["motional-emf", "flux-change", "rectangular-loop"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in electromagnetic induction in the correct chronological order:\n(I) Change in magnetic flux through the coil\n(II) Relative motion between magnet and coil\n(III) Induced EMF appears across the coil\n(IV) Induced current flows in the closed circuit", "explanation": "First there must be relative motion (II), which causes a change in flux (I), which by Faraday''s law produces an induced EMF (III), and if the circuit is closed, current flows (IV).", "payload": {"question_id": "cuet-phy-emi-faraday-ls01", "subtopic": "Steps in electromagnetic induction", "topic_name": "Faraday''s Law and Lenz''s Law", "bloom_level": "understand", "options": [{"key": "A", "text": "II → I → III → IV", "is_correct": true}, {"key": "B", "text": "I → II → III → IV", "is_correct": false}, {"key": "C", "text": "III → I → II → IV", "is_correct": false}, {"key": "D", "text": "II → III → I → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Flux change doesn''t happen on its own — relative motion must cause it first.", "misconception": "Thinking flux changes spontaneously"}, {"option_key": "C", "hint": "EMF is the result of flux change, not the cause.", "misconception": "Reversing cause and effect"}, {"option_key": "D", "hint": "EMF appears because of flux change, not before it.", "misconception": "EMF before flux change"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["electromagnetic-induction", "faraday-law", "induced-current"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the current growth in an LR circuit: I(t) = I₀(1 − e^(−t/τ)) where τ = L/R. At time t = L/R (one time constant), what fraction of the maximum current is reached?", "explanation": "At t = τ = L/R: I = I₀(1 − e⁻¹) = I₀(1 − 0.368) = 0.632 I₀ = 63.2% of maximum current.", "payload": {"question_id": "cuet-phy-emi-induct-d01", "subtopic": "LR circuit transient response", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "text": "50%", "is_correct": false}, {"key": "B", "text": "63.2%", "is_correct": true}, {"key": "C", "text": "37%", "is_correct": false}, {"key": "D", "text": "100%", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "50% is reached at t = 0.693τ (= τ × ln2), not at t = τ.", "misconception": "Confusing half-life with time constant"}, {"option_key": "C", "hint": "37% = e⁻¹ is the fraction remaining to reach, not the fraction already reached.", "misconception": "Using e⁻¹ instead of (1−e⁻¹)"}, {"option_key": "D", "hint": "100% is only reached at t → ∞.", "misconception": null}], "image_uri": "diagrams/cuet-phy-emi-induct-d01.png", "image_alt": "I vs t curve for LR circuit, current rises exponentially toward I₀, time constant τ=L/R marked"}, "image_alt": "I vs t curve for LR circuit, current rises exponentially toward I₀, time constant τ=L/R marked", "correct_answer": "B", "concept_tags": ["LR-circuit", "time-constant", "current-growth"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows two coils placed close together. The primary coil is connected to an AC source. If the mutual inductance between the coils is M and the current in the primary changes at rate dI/dt, what is the induced EMF in the secondary?", "explanation": "By the definition of mutual inductance: EMF₂ = M × dI₁/dt. The mutual inductance M quantifies the flux linkage between the two coils.", "payload": {"question_id": "cuet-phy-emi-induct-d02", "subtopic": "Mutual inductance between coils", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "text": "M × dI/dt", "is_correct": true}, {"key": "B", "text": "L × dI/dt", "is_correct": false}, {"key": "C", "text": "M × I", "is_correct": false}, {"key": "D", "text": "M / (dI/dt)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "L × dI/dt gives self-induced EMF in the same coil, not the mutual EMF in the other coil.", "misconception": "Confusing self and mutual inductance"}, {"option_key": "C", "hint": "EMF depends on rate of change of current, not the current itself.", "misconception": "Using I instead of dI/dt"}, {"option_key": "D", "hint": "EMF is proportional to dI/dt, not inversely proportional.", "misconception": "Inverting the relationship"}], "image_uri": "diagrams/cuet-phy-emi-induct-d02.png", "image_alt": "Two coils: primary coil connected to AC source, secondary coil with galvanometer. Magnetic flux lines linking both coils."}, "image_alt": "Two coils: primary coil connected to AC source, secondary coil with galvanometer. Magnetic flux lines linking both coils.", "correct_answer": "A", "concept_tags": ["mutual-inductance", "induced-emf", "coupled-coils"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following inductors in order of increasing energy stored when carrying the same current I:\n(I) Inductor with inductance L\n(II) Inductor with inductance 2L\n(III) Inductor with inductance L/2", "explanation": "Energy stored U = ½LI². For same I: U ∝ L. So L/2 < L < 2L, giving order III → I → II.", "payload": {"question_id": "cuet-phy-emi-induct-ls01", "subtopic": "Energy in an inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "text": "III → I → II", "is_correct": true}, {"key": "B", "text": "II → I → III", "is_correct": false}, {"key": "C", "text": "I 