SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows an electromagnetic wave with the electric field E oscillating along the y-axis and the magnetic field B oscillating along the z-axis. What is the direction of wave propagation?", "explanation": "In an EM wave, E, B, and the direction of propagation are mutually perpendicular (right-hand rule). E × B gives the direction of propagation. If E is along y and B is along z, then E × B = y × z = x. The wave propagates along the x-axis.", "payload": {"question_id": "cuet-phy-emwave-d02", "subtopic": "EM wave propagation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Along x-axis (E × B direction)", "is_correct": true}, {"key": "B", "text": "Along y-axis", "is_correct": false}, {"key": "C", "text": "Along z-axis", "is_correct": false}, {"key": "D", "text": "Along negative x-axis", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The y-axis is the direction of E oscillation, not propagation.", "misconception": "Confusing E direction with propagation"}, {"option_key": "C", "hint": "The z-axis is the direction of B oscillation, not propagation.", "misconception": "Confusing B direction with propagation"}, {"option_key": "D", "hint": "Using right-hand rule: y × z = +x, not −x.", "misconception": "Error in cross product direction"}], "image_uri": "diagrams/cuet-phy-emwave-d02.png", "image_alt": "EM wave with E field oscillating along y-axis, B field along z-axis, wave propagating along x-axis"}, "image_alt": "EM wave with E field oscillating along y-axis, B field along z-axis, wave propagating along x-axis", "correct_answer": "A", "concept_tags": ["em-wave", "polarization", "propagation-direction"]}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following electromagnetic waves in order of increasing frequency:\n(I) Microwaves\n(II) X-rays\n(III) Visible light\n(IV) Infrared", "explanation": "Frequency order: Microwaves (~10⁹-10¹² Hz) < Infrared (~10¹²-4×10¹⁴ Hz) < Visible (~4×10¹⁴-7.5×10¹⁴ Hz) < X-rays (~10¹⁶-10¹⁹ Hz). So I → IV → III → II.", "payload": {"question_id": "cuet-phy-emwave-ls01", "subtopic": "EM wave frequency ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "I → IV → III → II", "is_correct": true}, {"key": "B", "text": "II → III → IV → I", "is_correct": false}, {"key": "C", "text": "I → III → IV → II", "is_correct": false}, {"key": "D", "text": "IV → I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing frequency.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Infrared has lower frequency than visible light — IV comes before III.", "misconception": "Placing visible before infrared"}, {"option_key": "D", "hint": "Microwaves have lower frequency than infrared.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["em-spectrum", "frequency-order", "wave-classification"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a circular loop bent into two semicircles of the same radius R, carrying current such that the currents in the two halves flow in opposite directions. What is the net magnetic field at the centre?", "explanation": "Each semicircle produces B = μ₀I/(4R) at the centre, but in opposite directions (one into page, one out). They cancel: B_net = 0.", "payload": {"question_id": "cuet-phy-mag-biot-d01", "subtopic": "Magnetic field of semicircular loops", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "D", "text": "2μ₀I/(4R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field of a full circular loop. Here the two halves oppose each other.", "misconception": "Treating as a complete loop"}, {"option_key": "C", "hint": "μ₀I/(4R) is from one semicircle only. The other cancels it.", "misconception": "Counting only one semicircle"}, {"option_key": "D", "hint": "The fields add only if currents flow in the same direction, not opposite.", "misconception": "Adding instead of subtracting"}], "image_uri": "diagrams/cuet-phy-mag-biot-d01.png", "image_alt": "Two semicircular loops of same radius connected, carrying current in opposite sense, B vectors at center pointing in opposite directions cancel"}, "image_alt": "Two semicircular loops of same radius connected, carrying current in opposite sense, B vectors at center pointing in opposite directions cancel", "correct_answer": "B", "concept_tags": ["biot-savart", "semicircular-loop", "superposition"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The graph shows B vs r for a long straight wire carrying current I = 10 A. Using B = μ₀I/(2πr), what is the magnetic field at a distance of 2 cm from the wire?", "explanation": "B = μ₀I/(2πr) = (4π×10⁻⁷ × 10)/(2π × 0.02) = (4π×10⁻⁶)/(0.04π) = 10⁻⁴ T = 1×10⁻⁴ T.", "payload": {"question_id": "cuet-phy-mag-biot-d02", "subtopic": "B field of a long straight wire", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "2×10⁻⁵ T", "is_correct": false}, {"key": "B", "text": "5×10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "1×10⁻⁴ T", "is_correct": true}, {"key": "D", "text": "2×10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2×10⁻⁵ T would be the field at r = 10 cm, not 2 cm.", "misconception": "Using wrong distance"}, {"option_key": "B", "hint": "5×10⁻⁵ T = field at r = 4 cm. Check your distance value.", "misconception": null}, {"option_key": "D", "hint": "2×10⁻⁴ T would be the field at r = 1 cm.", "misconception": "Using r = 1 cm instead of 2 cm"}], "image_uri": "diagrams/cuet-phy-mag-biot-d02.png", "image_alt": "B vs r graph: hyperbolic curve showing B = μ₀I/(2πr). Wire at r=0, B decreasing with distance"}, "image_alt": "B vs r graph: hyperbolic curve showing B = μ₀I/(2πr). Wire at r=0, B decreasing with distance", "correct_answer": "C", "concept_tags": ["biot-savart", "straight-wire", "magnetic-field-calculation"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following circular loops in order of increasing magnetic field at the centre, all carrying the same current I:\n(I) Loop of radius R\n(II) Loop of radius 2R\n(III) Loop of radius R/2", "explanation": "B at centre = μ₀I/(2r). So B ∝ 1/r. Larger radius → smaller B. Order: 2R(smallest B) < R < R/2(largest B). So II → I → III.", "payload": {"question_id": "cuet-phy-mag-biot-ls01", "subtopic": "B field at centre of circular loop", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "II → I → III", "is_correct": true}, {"key": "B", "text": "III → I → II", "is_correct": false}, {"key": "C", "text": "I → II → III", "is_correct": false}, {"key": "D", "text": "II → III → I", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing B.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Loop of radius 2R has weaker B than radius R (B ∝ 1/r).", "misconception": null}, {"option_key": "D", "hint": "R/2 gives the strongest B, so III should be last.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["circular-loop", "magnetic-field", "radius-dependence"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a proton entering a uniform magnetic field B (perpendicular to its velocity, into the page). It follows a circular path of radius r. If the speed of the proton is doubled, what is the new radius?", "explanation": "For circular motion in B field: r = mv/(qB). If v → 2v, then r → 2mv/(qB) = 2r. The radius doubles.", "payload": {"question_id": "cuet-phy-mag-force-d01", "subtopic": "Circular motion of charged particle in B field", "topic_name": "Lorentz Force and Motion in Magnetic Field", "bloom_level": "apply", "options": [{"key": "A", "text": "r/2", "is_correct": false}, {"key": "B", "text": "r", "is_correct": false}, {"key": "C", "text": "4r", "is_correct": false}, {"key": "D", "text": "2r", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "r/2 would mean radius halved. Since r ∝ v, doubling v doubles r.", "misconception": "Thinking r ∝ 1/v"}, {"option_key": "B", "hint": "Radius r depends on velocity. If v changes, r must change too.", "misconception": "Thinking radius is independent of speed"}, {"option_key": "C", "hint": "4r would mean r ∝ v². But r = mv/(qB), so r ∝ v (linear).", "misconception": "Using v² instead of v"}], "image_uri": "diagrams/cuet-phy-mag-force-d01.png", "image_alt": "Proton entering uniform B field (into page) perpendicular to velocity, following circular path of radius r"}, "image_alt": "Proton entering uniform B field (into page) perpendicular to velocity, following circular path of radius r", "correct_answer": "D", "concept_tags": ["lorentz-force", "circular-motion", "radius"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows two long parallel wires carrying currents I₁ and I₂ in the same direction. What is the nature of the force between them?", "explanation": "Two parallel wires carrying currents in the same direction attract each other. The magnetic field of one wire exerts a force on the current in the other, directed toward the first wire.", "payload": {"question_id": "cuet-phy-mag-force-d02", "subtopic": "Force between parallel current-carrying wires", "topic_name": "Lorentz Force and Motion in Magnetic Field", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Depends on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs when currents are in opposite directions.", "misconception": "Confusing same and opposite direction cases"}, {"option_key": "C", "hint": "Two current-carrying wires always exert force on each other.", "misconception": null}, {"option_key": "D", "hint": "The nature (attractive/repulsive) depends on direction, not magnitude.", "misconception": null}], "image_uri": "diagrams/cuet-phy-mag-force-d02.png", "image_alt": "Two parallel wires with currents I₁ and I₂ in same direction (upward), force arrows pointing toward each other"}, "image_alt": "Two parallel wires with currents I₁ and I₂ in same direction (upward), force arrows pointing toward each other", "correct_answer": "A", "concept_tags": ["parallel-wires", "force", "same-direction"]}]'::jsonb, 'correction-batch-3');

