SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following in order of increasing force on a 1 m conductor carrying 5 A in a uniform field B = 0.2 T at different angles θ to the field:\n(I) θ = 0°\n(II) θ = 30°\n(III) θ = 60°\n(IV) θ = 90°", "explanation": "F = BIl sinθ. F(0°) = 0, F(30°) = 0.5 N, F(60°) = 0.866 N, F(90°) = 1.0 N. Order: I → II → III → IV.", "payload": {"question_id": "cuet-phy-mag-force-ls01", "subtopic": "Force on current-carrying conductor", "topic_name": "Lorentz Force and Motion in Magnetic Field", "bloom_level": "apply", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → III → II → IV", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing force.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "sin 30° = 0.5 < sin 60° = 0.866, so II comes before III.", "misconception": "Wrong sine values"}, {"option_key": "D", "hint": "At θ = 0°, F = 0 (minimum). I should come first.", "misconception": "Thinking force is non-zero at 0°"}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["force-on-conductor", "angle-dependence", "magnetic-force"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a moving coil galvanometer with N turns, area A, magnetic field B, and spring constant k. What is the current sensitivity (deflection per unit current)?", "explanation": "At equilibrium: torque = restoring force, NIAB = kθ. Current sensitivity = θ/I = NAB/k.", "payload": {"question_id": "cuet-phy-mag-device-d01", "subtopic": "Moving coil galvanometer sensitivity", "topic_name": "Galvanometer, Ammeter, Voltmeter, Cyclotron", "bloom_level": "apply", "options": [{"key": "A", "text": "NAB", "is_correct": false}, {"key": "B", "text": "NAB/k", "is_correct": true}, {"key": "C", "text": "k/(NAB)", "is_correct": false}, {"key": "D", "text": "NB/(Ak)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB gives the torque per unit current, not the deflection per unit current (need to divide by k).", "misconception": "Forgetting the spring constant"}, {"option_key": "C", "hint": "k/(NAB) is the reciprocal — higher k means less sensitivity, not more.", "misconception": "Inverting the formula"}, {"option_key": "D", "hint": "A should be in the numerator (larger area = more torque = more sensitivity).", "misconception": null}], "image_uri": "diagrams/cuet-phy-mag-device-d01.png", "image_alt": "Moving coil galvanometer: rectangular coil between magnet poles, spring providing restoring torque, scale with pointer"}, "image_alt": "Moving coil galvanometer: rectangular coil between magnet poles, spring providing restoring torque, scale with pointer", "correct_answer": "B", "concept_tags": ["galvanometer", "current-sensitivity", "torque-balance"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a cyclotron with two D-shaped electrodes (dees) in a magnetic field B. A proton of mass m and charge q spirals outward. What is the cyclotron frequency?", "explanation": "The cyclotron frequency f = qB/(2πm). This is independent of the radius and speed of the particle — a key feature that makes the cyclotron work.", "payload": {"question_id": "cuet-phy-mag-device-d02", "subtopic": "Cyclotron frequency", "topic_name": "Galvanometer, Ammeter, Voltmeter, Cyclotron", "bloom_level": "remember", "options": [{"key": "A", "text": "qB/m", "is_correct": false}, {"key": "B", "text": "2πm/(qB)", "is_correct": false}, {"key": "C", "text": "qB/(2πm)", "is_correct": true}, {"key": "D", "text": "qBr/m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "qB/m = ω (angular frequency). The cyclotron frequency f = ω/(2π).", "misconception": "Confusing angular frequency with frequency"}, {"option_key": "B", "hint": "2πm/(qB) = 1/f = T (the time period), not the frequency.", "misconception": "Giving time period instead of frequency"}, {"option_key": "D", "hint": "Cyclotron frequency is independent of radius r.", "misconception": "Including radius in frequency"}], "image_uri": "diagrams/cuet-phy-mag-device-d02.png", "image_alt": "Cyclotron top view: two D-shaped electrodes (dees), magnetic field B perpendicular to plane, proton spiraling outward"}, "image_alt": "Cyclotron top view: two D-shaped electrodes (dees), magnetic field B perpendicular to plane, proton spiraling outward", "correct_answer": "C", "concept_tags": ["cyclotron", "frequency", "charged-particle"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following in order of increasing total resistance for converting a galvanometer (resistance G) to the specified instrument:\n(I) Ammeter (0-1 A)\n(II) Ammeter (0-10 A)\n(III) Voltmeter (0-10 V)", "explanation": "Ammeter uses low shunt resistance S = GIg/(I-Ig). Larger range → smaller S. So 0-10A ammeter has smallest total R. 0-1A ammeter has slightly larger R. Voltmeter uses high series resistance R_total >> G. Order: II → I → III.", "payload": {"question_id": "cuet-phy-mag-device-ls01", "subtopic": "Galvanometer conversion", "topic_name": "Galvanometer, Ammeter, Voltmeter, Cyclotron", "bloom_level": "analyze", "options": [{"key": "A", "text": "II → I → III", "is_correct": true}, {"key": "B", "text": "III → I → II", "is_correct": false}, {"key": "C", "text": "I → II → III", "is_correct": false}, {"key": "D", "text": "II → III → I", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Voltmeter has the highest resistance (series R), not the lowest.", "misconception": "Reversing ammeter and voltmeter resistance"}, {"option_key": "C", "hint": "Higher range ammeter needs smaller shunt, giving lower total resistance.", "misconception": null}, {"option_key": "D", "hint": "Voltmeter resistance is much higher than any ammeter.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["ammeter", "voltmeter", "galvanometer-conversion"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a magnetic dipole of moment M placed in a uniform magnetic field B at angle θ. The torque τ = MB sinθ. For what value of θ is the torque maximum?", "explanation": "τ = MB sinθ. Maximum when sinθ = 1, i.e., θ = 90°. At this angle, the dipole is perpendicular to the field.", "payload": {"question_id": "cuet-phy-mag-dipole-d01", "subtopic": "Torque on magnetic dipole", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "0°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "At 0°, sinθ = 0, so τ = 0. This is the equilibrium position.", "misconception": "Confusing stable equilibrium with maximum torque"}, {"option_key": "B", "hint": "At 45°, sin 45° = 0.707 — not the maximum value of sine.", "misconception": null}, {"option_key": "C", "hint": "At 180°, sin 180° = 0, so τ = 0. This is unstable equilibrium.", "misconception": "Confusing unstable equilibrium with maximum torque"}], "image_uri": "diagrams/cuet-phy-mag-dipole-d01.png", "image_alt": "Bar magnet (magnetic moment M) at angle θ to uniform magnetic field B, torque τ rotating it toward field direction"}, "image_alt": "Bar magnet (magnetic moment M) at angle θ to uniform magnetic field B, torque τ rotating it toward field direction", "correct_answer": "D", "concept_tags": ["magnetic-dipole", "torque", "uniform-field"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows the magnetic field lines of a bar magnet. Where is the magnetic field strongest?", "explanation": "Magnetic field strength is proportional to the density of field lines. Near the poles, field lines are most closely packed, indicating the strongest field.", "payload": {"question_id": "cuet-phy-mag-dipole-d02", "subtopic": "Magnetic field of a bar magnet", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "At the poles", "is_correct": true}, {"key": "B", "text": "At the centre of the magnet", "is_correct": false}, {"key": "C", "text": "Midway between N and S outside the magnet", "is_correct": false}, {"key": "D", "text": "Field is uniform everywhere", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Inside the magnet at the centre, the field exists but is not the strongest point externally.", "misconception": null}, {"option_key": "C", "hint": "The field lines are more spread out far from the poles — weaker field.", "misconception": null}, {"option_key": "D", "hint": "A bar magnet''s field is non-uniform — it varies with position.", "misconception": "Assuming uniform field"}], "image_uri": "diagrams/cuet-phy-mag-dipole-d02.png", "image_alt": "Bar magnet with N and S poles, field lines emerging from N, curving around, entering S. Lines densest near poles."}, "image_alt": "Bar magnet with N and S poles, field lines emerging from N, curving around, entering S. Lines densest near poles.", "correct_answer": "A", "concept_tags": ["magnetic-field-lines", "bar-magnet", "poles"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following positions of a magnetic dipole M in uniform field B in order of increasing potential energy:\n(I) θ = 0° (aligned with B)\n(II) θ = 90° (perpendicular to B)\n(III) θ = 180° (anti-aligned with B)", "explanation": "U = −MB cosθ. U(0°) = −MB (minimum), U(90°) = 0, U(180°) = +MB (maximum). Order: I → II → III.", "payload": {"question_id": "cuet-phy-mag-dipole-ls01", "subtopic": "Potential energy of dipole in field", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing potential energy.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "U(0°) = −MB is less than U(90°) = 0, so I comes before II.", "misconception": null}, {"option_key": "D", "hint": "U(180°) = +MB > U(90°) = 0, so III comes after II.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["potential-energy", "magnetic-dipole", "orientation"]}]'::jsonb, 'correction-batch-3');

