SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the B-H hysteresis curve for a ferromagnetic material. What does the area enclosed by the hysteresis loop represent?", "explanation": "The area of the hysteresis loop represents the energy dissipated as heat per unit volume per magnetization cycle. Materials with larger loops (hard magnets) dissipate more energy.", "payload": {"question_id": "cuet-phy-mag-mat-d01", "subtopic": "Hysteresis loop and energy loss", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic susceptibility of the material", "is_correct": false}, {"key": "B", "text": "Energy dissipated per cycle per unit volume", "is_correct": true}, {"key": "C", "text": "The retentivity of the material", "is_correct": false}, {"key": "D", "text": "The coercivity of the material", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Susceptibility is the slope of the B-H curve, not the area.", "misconception": "Confusing slope with area"}, {"option_key": "C", "hint": "Retentivity is the y-intercept (B when H=0), a single point, not the area.", "misconception": null}, {"option_key": "D", "hint": "Coercivity is the x-intercept (H when B=0), a single point, not the area.", "misconception": null}], "image_uri": "diagrams/cuet-phy-mag-mat-d01.png", "image_alt": "B-H hysteresis curve: S-shaped loop showing B vs H for ferromagnetic material, with retentivity Br and coercivity Hc marked"}, "image_alt": "B-H hysteresis curve: S-shaped loop showing B vs H for ferromagnetic material, with retentivity Br and coercivity Hc marked", "correct_answer": "B", "concept_tags": ["hysteresis", "energy-loss", "ferromagnetic"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The graph shows the variation of magnetic susceptibility (χ) with temperature (T) for a paramagnetic material. According to Curie''s law, χ is proportional to:", "explanation": "Curie''s law: χ = C/T, where C is the Curie constant. So χ ∝ 1/T. As temperature increases, thermal agitation randomizes magnetic moments, reducing susceptibility.", "payload": {"question_id": "cuet-phy-mag-mat-d02", "subtopic": "Temperature dependence of susceptibility", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "1/T", "is_correct": true}, {"key": "B", "text": "T", "is_correct": false}, {"key": "C", "text": "T²", "is_correct": false}, {"key": "D", "text": "Independent of T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "χ ∝ T would mean susceptibility increases with temperature — opposite of Curie''s law.", "misconception": "Inverting the relationship"}, {"option_key": "C", "hint": "There is no T² dependence in Curie''s law.", "misconception": null}, {"option_key": "D", "hint": "Diamagnetic susceptibility is roughly independent of T, but paramagnetic follows Curie''s law.", "misconception": "Confusing para with diamagnetic"}], "image_uri": "diagrams/cuet-phy-mag-mat-d02.png", "image_alt": "χ vs T graph: hyperbolic decrease showing χ ∝ 1/T (Curie''s law) for paramagnetic material. χ approaches zero at high T."}, "image_alt": "χ vs T graph: hyperbolic decrease showing χ ∝ 1/T (Curie''s law) for paramagnetic material. χ approaches zero at high T.", "correct_answer": "A", "concept_tags": ["curie-law", "susceptibility", "paramagnetic"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following materials in order of increasing magnetic susceptibility:\n(I) Diamagnetic (copper)\n(II) Paramagnetic (aluminium)\n(III) Ferromagnetic (iron)", "explanation": "Diamagnetic: χ ≈ −10⁻⁵ (small, negative). Paramagnetic: χ ≈ +10⁻⁵ to +10⁻³ (small, positive). Ferromagnetic: χ ≈ +10³ to +10⁵ (very large, positive). Order: I → II → III.", "payload": {"question_id": "cuet-phy-mag-mat-ls01", "subtopic": "Comparison of magnetic materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing susceptibility.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Diamagnetic has negative χ, the smallest value.", "misconception": null}, {"option_key": "D", "hint": "Ferromagnetic has the highest χ by far (thousands).", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["susceptibility", "magnetic-materials", "classification"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The ray diagram shows an object placed between the focus (F) and centre of curvature (C) of a concave mirror. The image formed is:", "explanation": "When the object is between F and C, the image is formed beyond C. It is real (on the same side as object), inverted, and magnified (larger than object).", "payload": {"question_id": "cuet-phy-ray-reflect-d01", "subtopic": "Image formation by concave mirror", "topic_name": "Reflection at Curved Surfaces and Mirror Formula", "bloom_level": "understand", "options": [{"key": "A", "text": "Virtual, erect, magnified", "is_correct": false}, {"key": "B", "text": "Real, inverted, diminished", "is_correct": false}, {"key": "C", "text": "Real, inverted, magnified", "is_correct": true}, {"key": "D", "text": "Real, inverted, same size", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Virtual, erect image is formed only when object is between F and pole.", "misconception": "Wrong object position"}, {"option_key": "B", "hint": "Diminished image is formed when object is beyond C.", "misconception": "Confusing ''between F and C'' with ''beyond C''"}, {"option_key": "D", "hint": "Same size image is formed when object is at C.", "misconception": "Confusing ''between F and C'' with ''at C''"}], "image_uri": "diagrams/cuet-phy-ray-reflect-d01.png", "image_alt": "Concave mirror with center of curvature C and focus F. Object between F and C. Two rays drawn forming real, inverted, magnified image beyond C."}, "image_alt": "Concave mirror with center of curvature C and focus F. Object between F and C. Two rays drawn forming real, inverted, magnified image beyond C.", "correct_answer": "C", "concept_tags": ["concave-mirror", "image-formation", "ray-diagram"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The graph shows 1/v vs 1/u for a concave mirror, which is a straight line. What is its slope?", "explanation": "Mirror formula: 1/v + 1/u = 1/f. Rearranging: 1/v = −(1/u) + 1/f. Comparing with y = mx + c: slope m = −1.", "payload": {"question_id": "cuet-phy-ray-reflect-d02", "subtopic": "Mirror formula graphical representation", "topic_name": "Reflection at Curved Surfaces and Mirror Formula", "bloom_level": "understand", "options": [{"key": "A", "text": "+1", "is_correct": false}, {"key": "B", "text": "−1", "is_correct": true}, {"key": "C", "text": "1/f", "is_correct": false}, {"key": "D", "text": "−1/f", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The coefficient of 1/u is −1, not +1.", "misconception": "Sign error in rearrangement"}, {"option_key": "C", "hint": "1/f is the y-intercept, not the slope.", "misconception": "Confusing slope with intercept"}, {"option_key": "D", "hint": "−1/f is neither the slope nor the intercept in this form.", "misconception": null}], "image_uri": "diagrams/cuet-phy-ray-reflect-d02.png", "image_alt": "Graph of 1/v vs 1/u: straight line with slope −1, y-intercept = 1/f"}, "image_alt": "Graph of 1/v vs 1/u: straight line with slope −1, y-intercept = 1/f", "correct_answer": "B", "concept_tags": ["mirror-formula", "graphical-analysis", "concave-mirror"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following object positions for a concave mirror in order of increasing image size:\n(I) Object at infinity\n(II) Object at C\n(III) Object between F and C\n(IV) Object at F", "explanation": "At infinity: image at F, point-sized. At C: image at C, same size. Between F and C: image beyond C, magnified. At F: image at infinity, infinitely large. Order: I → II → III → IV.", "payload": {"question_id": "cuet-phy-ray-reflect-ls01", "subtopic": "Image size variation with object position", "topic_name": "Reflection at Curved Surfaces and Mirror Formula", "bloom_level": "analyze", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → III → II → IV", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing image size.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "At C, image is same size (m=1). Between F and C, image is magnified (m>1).", "misconception": null}, {"option_key": "D", "hint": "At infinity, image is point-sized (smallest), not after C.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["concave-mirror", "image-size", "object-position"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows light passing through a prism of angle A = 60° at minimum deviation δ_min = 30°. At minimum deviation, i = e. What is the refractive index of the prism?", "explanation": "At minimum deviation: μ = sin((A + δ_min)/2) / sin(A/2) = sin((60°+30°)/2) / sin(60°/2) = sin(45°)/sin(30°) = (√2/2)/(1/2) = √2 ≈ 1.414.", "payload": {"question_id": "cuet-phy-ray-prism-d01", "subtopic": "Prism formula at minimum deviation", "topic_name": "Refraction through Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "1.5", "is_correct": false}, {"key": "B", "text": "√2 ≈ 1.414", "is_correct": true}, {"key": "C", "text": "√3 ≈ 1.732", "is_correct": false}, {"key": "D", "text": "2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.5 = sin(45°)/sin(30°) only if you use sin(45°) = 0.75, but sin(45°) = 0.707.", "misconception": null}, {"option_key": "C", "hint": "√3 would require sin((A+δ)/2)/sin(A/2) = sin(60°)/sin(30°). Check your angles.", "misconception": "Using wrong angles in formula"}, {"option_key": "D", "hint": "μ = 2 is very high for glass. sin(45°)/sin(30°) ≠ 2.", "misconception": null}], "image_uri": "diagrams/cuet-phy-ray-prism-d01.png", "image_alt": "Prism of angle A=60°, light ray entering and exiting symmetrically at minimum deviation δ=30°, i=e"}, "image_alt": "Prism of angle A=60°, light ray entering and exiting symmetrically at minimum deviation δ=30°, i=e", "correct_answer": "B", "concept_tags": ["prism", "minimum-deviation", "refractive-index"]}]'::jsonb, 'correction-batch-3');

