SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows white light being dispersed by a glass prism into the visible spectrum. Which colour deviates the most?", "explanation": "Violet light has the shortest wavelength and highest refractive index in glass, so it deviates the most. Red has the longest wavelength and deviates the least.", "payload": {"question_id": "cuet-phy-ray-prism-d02", "subtopic": "Dispersion of white light", "topic_name": "Refraction through Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Green", "is_correct": false}, {"key": "C", "text": "Yellow", "is_correct": false}, {"key": "D", "text": "Violet", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red has the longest wavelength and deviates the LEAST.", "misconception": "Confusing most with least deviation"}, {"option_key": "B", "hint": "Green is in the middle of the spectrum — moderate deviation.", "misconception": null}, {"option_key": "C", "hint": "Yellow is also intermediate. Shortest wavelength = most deviation.", "misconception": null}], "image_uri": "diagrams/cuet-phy-ray-prism-d02.png", "image_alt": "White light entering prism, dispersed into spectrum VIBGYOR. Violet bent most, red bent least."}, "image_alt": "White light entering prism, dispersed into spectrum VIBGYOR. Violet bent most, red bent least.", "correct_answer": "D", "concept_tags": ["dispersion", "prism", "deviation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following colours of visible light in order of increasing refractive index in glass:\n(I) Red\n(II) Yellow\n(III) Blue\n(IV) Violet", "explanation": "Refractive index increases with frequency (decreases with wavelength). Red has lowest μ, violet has highest. Order: I → II → III → IV.", "payload": {"question_id": "cuet-phy-ray-prism-ls01", "subtopic": "Refractive index vs colour", "topic_name": "Refraction through Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "I → II → III → IV", "is_correct": true}, {"key": "B", "text": "IV → III → II → I", "is_correct": false}, {"key": "C", "text": "I → III → II → IV", "is_correct": false}, {"key": "D", "text": "II → I → III → IV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing refractive index.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Yellow has lower μ than blue (yellow wavelength > blue wavelength).", "misconception": null}, {"option_key": "D", "hint": "Red has the lowest μ, so I comes first.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["refractive-index", "dispersion", "colour-dependence"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a compound microscope with objective (fo = 1 cm) and eyepiece (fe = 5 cm), tube length L = 20 cm. What is the approximate magnification?", "explanation": "Magnification m ≈ (L/fo)(D/fe) = (20/1)(25/5) = 20 × 5 = 100, where D = 25 cm (least distance of distinct vision).", "payload": {"question_id": "cuet-phy-ray-instr-d01", "subtopic": "Compound microscope magnification", "topic_name": "Optical Instruments (Microscope and Telescope)", "bloom_level": "apply", "options": [{"key": "A", "text": "20", "is_correct": false}, {"key": "B", "text": "50", "is_correct": false}, {"key": "C", "text": "100", "is_correct": true}, {"key": "D", "text": "200", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "20 = L/fo. You forgot to multiply by D/fe = 25/5 = 5.", "misconception": "Using only objective magnification"}, {"option_key": "B", "hint": "50 would result from using D = 25 directly instead of D/fe.", "misconception": null}, {"option_key": "D", "hint": "200 would require either a different tube length or focal lengths.", "misconception": null}], "image_uri": "diagrams/cuet-phy-ray-instr-d01.png", "image_alt": "Compound microscope: objective lens (fo=1cm) forms magnified real image, eyepiece (fe=5cm) acts as magnifier. Tube length L=20cm."}, "image_alt": "Compound microscope: objective lens (fo=1cm) forms magnified real image, eyepiece (fe=5cm) acts as magnifier. Tube length L=20cm.", "correct_answer": "C", "concept_tags": ["compound-microscope", "magnification", "optical-instruments"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows an astronomical telescope in normal adjustment (image at infinity). The magnifying power in this mode is:", "explanation": "In normal adjustment (image at infinity): M = fo/fe, where fo is the focal length of the objective and fe is the focal length of the eyepiece.", "payload": {"question_id": "cuet-phy-ray-instr-d02", "subtopic": "Astronomical telescope magnification", "topic_name": "Optical Instruments (Microscope and Telescope)", "bloom_level": "remember", "options": [{"key": "A", "text": "fo/fe", "is_correct": true}, {"key": "B", "text": "fe/fo", "is_correct": false}, {"key": "C", "text": "fo × fe", "is_correct": false}, {"key": "D", "text": "fo + fe", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fe/fo < 1 (since fo > fe), giving magnification less than 1 — that defeats the purpose.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "fo × fe has units of cm², not a dimensionless ratio.", "misconception": null}, {"option_key": "D", "hint": "fo + fe gives the tube length in normal adjustment, not magnification.", "misconception": "Confusing tube length with magnification"}], "image_uri": "diagrams/cuet-phy-ray-instr-d02.png", "image_alt": "Astronomical telescope: objective (large fo) forms image at focus, eyepiece (small fe) views it. Parallel rays in and out."}, "image_alt": "Astronomical telescope: objective (large fo) forms image at focus, eyepiece (small fe) views it. Parallel rays in and out.", "correct_answer": "A", "concept_tags": ["telescope", "magnifying-power", "normal-adjustment"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange in order of increasing magnifying power for normal adjustment:\n(I) Simple magnifier (D/f = 5)\n(II) Compound microscope (m = 100)\n(III) Astronomical telescope (m = 50)", "explanation": "Simple magnifier: m = 5. Telescope: m = 50. Microscope: m = 100. Order: I → III → II.", "payload": {"question_id": "cuet-phy-ray-instr-ls01", "subtopic": "Comparison of optical instruments", "topic_name": "Optical Instruments (Microscope and Telescope)", "bloom_level": "analyze", "options": [{"key": "A", "text": "I → III → II", "is_correct": true}, {"key": "B", "text": "II → III → I", "is_correct": false}, {"key": "C", "text": "I → II → III", "is_correct": false}, {"key": "D", "text": "III → I → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the order of decreasing magnification.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Microscope (100) has higher magnification than telescope (50).", "misconception": null}, {"option_key": "D", "hint": "Simple magnifier (5) has the lowest magnification.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["magnification-comparison", "optical-instruments"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "In the diagram of Young''s double-slit experiment, two coherent sources S₁ and S₂ are separated by distance d and a screen is placed at distance D. The fringe width β is observed. Which expression correctly gives β?", "explanation": "Fringe width β = λD/d. It is directly proportional to wavelength λ and screen distance D, and inversely proportional to slit separation d.", "payload": {"question_id": "cuet-phy-waveopt-interf-d01", "subtopic": "Fringe width formula", "topic_name": "Interference and Young''s Double Slit", "bloom_level": "understand", "options": [{"key": "A", "text": "β = λd/D", "is_correct": false}, {"key": "B", "text": "β = λD/d", "is_correct": true}, {"key": "C", "text": "β = d/(λD)", "is_correct": false}, {"key": "D", "text": "β = D/(λd)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This inverts D and d. Increasing slit separation d should decrease fringe width, not increase it.", "misconception": "Swapping d and D"}, {"option_key": "C", "hint": "Fringe width increases with wavelength, so λ should be in the numerator.", "misconception": null}, {"option_key": "D", "hint": "λ must appear in the numerator — longer wavelength gives wider fringes.", "misconception": null}], "image_uri": "diagrams/cuet-phy-waveopt-interf-d01.png", "image_alt": "Young''s double-slit setup: two slits S1, S2 separated by d, screen at distance D, fringes with width β marked"}, "image_alt": "Young''s double-slit setup: two slits S1, S2 separated by d, screen at distance D, fringes with width β marked", "correct_answer": "B", "concept_tags": ["YDSE", "fringe-width", "interference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The intensity pattern from a double-slit experiment is shown. If the path difference at point P is λ/3, and I₀ is the intensity due to each slit, what is the resultant intensity at P?", "explanation": "Phase difference δ = (2π/λ)(λ/3) = 2π/3. Resultant intensity I = 4I₀cos²(δ/2) = 4I₀cos²(π/3) = 4I₀(1/2)² = 4I₀(1/4) = I₀.", "payload": {"question_id": "cuet-phy-waveopt-interf-d02", "subtopic": "Intensity at arbitrary point", "topic_name": "Interference and Young''s Double Slit", "bloom_level": "apply", "options": [{"key": "A", "text": "4I₀", "is_correct": false}, {"key": "B", "text": "2I₀", "is_correct": false}, {"key": "C", "text": "I₀", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4I₀ occurs only at path difference = nλ (constructive maximum). λ/3 is not an integer multiple of λ.", "misconception": "Assuming maximum everywhere"}, {"option_key": "B", "hint": "2I₀ would require cos²(δ/2) = 1/2, i.e., δ/2 = π/4, which gives path difference λ/4, not λ/3.", "misconception": null}, {"option_key": "D", "hint": "Zero intensity requires path difference (n+½)λ (destructive). λ/3 ≠ λ/2.", "misconception": "Confusing with destructive condition"}], "image_uri": "diagrams/cuet-phy-waveopt-interf-d02.png", "image_alt": "Double-slit intensity pattern with point P marked where path difference is λ/3, showing intensity distribution curve"}, "image_alt": "Double-slit intensity pattern with point P marked where path difference is λ/3, showing intensity distribution curve", "correct_answer": "C", "concept_tags": ["interference-intensity", "phase-difference", "path-difference"]}]'::jsonb, 'correction-batch-3');

