SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following YDSE setups in order of increasing fringe width:\n(I) λ = 500 nm, d = 1 mm, D = 1 m (β = 0.5 mm)\n(II) λ = 600 nm, d = 0.5 mm, D = 1 m (β = 1.2 mm)\n(III) λ = 700 nm, d = 0.5 mm, D = 2 m (β = 2.8 mm)", "explanation": "Using β = λD/d: Setup I: 0.5 mm, Setup II: 1.2 mm, Setup III: 2.8 mm. Order: I → II → III.", "payload": {"question_id": "cuet-phy-waveopt-interf-ls01", "subtopic": "Fringe width comparison", "topic_name": "Interference and Young''s Double Slit", "bloom_level": "analyze", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This gives decreasing fringe width, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "Calculate β for II: 600e-9 × 1 / 0.5e-3 = 1.2 mm, which is larger than I''s 0.5 mm.", "misconception": null}, {"option_key": "D", "hint": "β for III (2.8 mm) is larger than β for II (1.2 mm), so III must come last.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["fringe-width-comparison", "YDSE"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows single-slit Fraunhofer diffraction. A slit of width a produces the first minimum at angle θ. Which condition gives the position of the first minimum?", "explanation": "For single-slit diffraction, the first minimum occurs when a sinθ = λ, where a is the slit width. This is because the slit is divided into two halves that cancel pairwise.", "payload": {"question_id": "cuet-phy-waveopt-diff-d01", "subtopic": "Condition for minima", "topic_name": "Diffraction and Single Slit", "bloom_level": "understand", "options": [{"key": "A", "text": "a sinθ = λ", "is_correct": true}, {"key": "B", "text": "a sinθ = λ/2", "is_correct": false}, {"key": "C", "text": "a cosθ = λ", "is_correct": false}, {"key": "D", "text": "a sinθ = 2λ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "a sinθ = λ/2 would be a subsidiary maximum, not a minimum.", "misconception": "Confusing maxima and minima conditions"}, {"option_key": "C", "hint": "Path difference depends on sinθ not cosθ for rays from different parts of the slit.", "misconception": null}, {"option_key": "D", "hint": "a sinθ = 2λ gives the second minimum, not the first.", "misconception": "Using wrong order number"}], "image_uri": "diagrams/cuet-phy-waveopt-diff-d01.png", "image_alt": "Single slit of width a with parallel rays, showing first minimum at angle θ, with path difference a sinθ = λ marked"}, "image_alt": "Single slit of width a with parallel rays, showing first minimum at angle θ, with path difference a sinθ = λ marked", "correct_answer": "A", "concept_tags": ["single-slit-diffraction", "first-minimum"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram compares two single-slit diffraction patterns — one with slit width a, and one with slit width a/2. How does the angular width of the central maximum change when the slit width is halved?", "explanation": "Angular position of first minimum: sinθ ≈ θ = λ/a. Angular width of central max = 2λ/a. Halving slit width: new width = 2λ/(a/2) = 4λ/a — the angular width doubles.", "payload": {"question_id": "cuet-phy-waveopt-diff-d02", "subtopic": "Width of central maximum", "topic_name": "Diffraction and Single Slit", "bloom_level": "apply", "options": [{"key": "A", "text": "It halves", "is_correct": false}, {"key": "B", "text": "It remains the same", "is_correct": false}, {"key": "C", "text": "It increases by 50%", "is_correct": false}, {"key": "D", "text": "It doubles", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Narrower slit produces wider diffraction — not narrower. This is a common inverse relationship error.", "misconception": "Thinking narrower slit gives narrower pattern"}, {"option_key": "B", "hint": "Angular width = 2λ/a clearly depends on a, so changing a must change the width.", "misconception": null}, {"option_key": "C", "hint": "Halving a doubles 1/a, so the width doubles (not 1.5×).", "misconception": null}], "image_uri": "diagrams/cuet-phy-waveopt-diff-d02.png", "image_alt": "Two diffraction patterns compared: slit width a (narrow central max) and slit width a/2 (wide central max), showing angular width 2θ doubles"}, "image_alt": "Two diffraction patterns compared: slit width a (narrow central max) and slit width a/2 (wide central max), showing angular width 2θ doubles", "correct_answer": "D", "concept_tags": ["diffraction-pattern", "central-maximum-width"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following single-slit setups in order of increasing angular width of the central maximum:\n(I) a = 0.2 mm, λ = 500 nm → 2θ = 5 mrad\n(II) a = 0.1 mm, λ = 500 nm → 2θ = 10 mrad\n(III) a = 0.1 mm, λ = 700 nm → 2θ = 14 mrad", "explanation": "Angular width 2θ = 2λ/a. Setup I: 5 mrad, Setup II: 10 mrad, Setup III: 14 mrad. Order: I → II → III.", "payload": {"question_id": "cuet-phy-waveopt-diff-ls01", "subtopic": "Angular width comparison", "topic_name": "Diffraction and Single Slit", "bloom_level": "analyze", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is decreasing order of angular width.", "misconception": "Reversing the sequence"}, {"option_key": "C", "hint": "Setup I (5 mrad) has a smaller angular width than Setup II (10 mrad), so I comes before II.", "misconception": null}, {"option_key": "D", "hint": "Setup III (14 mrad) is the largest, so it must come last.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["angular-width-comparison", "diffraction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows unpolarised light incident on a glass surface at Brewster''s angle. The reflected ray is fully polarised. If the reflected and refracted rays are perpendicular, and the Brewster angle is 57°, what is the refractive index of the glass?", "explanation": "At Brewster''s angle: μ = tan(iB) = tan(57°) ≈ 1.54. The reflected and refracted rays are perpendicular (i + r = 90°), a defining property of Brewster''s angle.", "payload": {"question_id": "cuet-phy-waveopt-polar-d01", "subtopic": "Brewster''s angle and refractive index", "topic_name": "Polarisation and Brewster''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.33", "is_correct": false}, {"key": "B", "text": "1.54", "is_correct": true}, {"key": "C", "text": "1.73", "is_correct": false}, {"key": "D", "text": "1.00", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.33 is the refractive index of water (Brewster angle ≈ 53°), not glass at 57°.", "misconception": "Using water''s refractive index"}, {"option_key": "C", "hint": "tan(60°) = 1.73. Brewster''s angle for μ = 1.73 would be 60°, not 57°.", "misconception": "Using wrong angle"}, {"option_key": "D", "hint": "μ = 1.00 means no interface (Brewster angle = 45° for equal media). The question specifies a glass surface.", "misconception": null}], "image_uri": "diagrams/cuet-phy-waveopt-polar-d01.png", "image_alt": "Light ray hitting glass at Brewster angle 57°, reflected ray polarised, refracted ray at 33° with perpendicular annotation between reflected and refracted"}, "image_alt": "Light ray hitting glass at Brewster angle 57°, reflected ray polarised, refracted ray at 33° with perpendicular annotation between reflected and refracted", "correct_answer": "B", "concept_tags": ["brewster-angle", "polarisation", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram illustrates Malus''s Law. Unpolarised light of intensity I₀ passes through a polariser and then through an analyser whose pass axis makes an angle of 60° with the polariser. What is the intensity of light emerging from the analyser?", "explanation": "After the polariser: I₁ = I₀/2. After the analyser (Malus''s Law): I₂ = I₁cos²(60°) = (I₀/2)(1/2)² = (I₀/2)(1/4) = I₀/8.", "payload": {"question_id": "cuet-phy-waveopt-polar-d02", "subtopic": "Malus''s Law application", "topic_name": "Polarisation and Brewster''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": false}, {"key": "C", "text": "I₀/8", "is_correct": true}, {"key": "D", "text": "I₀/16", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 is the intensity after the first polariser only. You still need to apply Malus''s law at the analyser.", "misconception": "Forgetting the analyser"}, {"option_key": "B", "hint": "I₀/4 would be the answer if cos²(60°) = 1/2, but cos(60°) = 1/2 so cos²(60°) = 1/4.", "misconception": "Using cos instead of cos²"}, {"option_key": "D", "hint": "I₀/16 would require cos²θ = 1/8, which gives θ ≈ 69.3°, not 60°.", "misconception": null}], "image_uri": "diagrams/cuet-phy-waveopt-polar-d02.png", "image_alt": "Unpolarised light (I₀) → polariser (I₀/2) → analyser at 60° → transmitted intensity marked with question mark"}, "image_alt": "Unpolarised light (I₀) → polariser (I₀/2) → analyser at 60° → transmitted intensity marked with question mark", "correct_answer": "C", "concept_tags": ["malus-law", "polarisation", "intensity"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Unpolarised light of intensity I₀ passes through a polariser. The polarised light then passes through analysers at different angles. Arrange in order of increasing transmitted intensity:\n(I) Analyser at 60° → I = I₀cos²60°/2 = I₀/8\n(II) Analyser at 45° → I = I₀cos²45°/2 = I₀/4\n(III) Analyser at 30° → I = I₀cos²30°/2 = 3I₀/8", "explanation": "After polariser, I₁ = I₀/2. Applying Malus''s law: At 60°: I₀/8, at 45°: I₀/4, at 30°: 3I₀/8. Order of increasing intensity: I → II → III.", "payload": {"question_id": "cuet-phy-waveopt-polar-ls01", "subtopic": "Malus''s law intensity comparison", "topic_name": "Polarisation and Brewster''s Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "I → II → III", "is_correct": true}, {"key": "B", "text": "III → II → I", "is_correct": false}, {"key": "C", "text": "II → I → III", "is_correct": false}, {"key": "D", "text": "I → III → II", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is decreasing intensity order, not increasing.", "misconception": "Reversing the sequence"}, {"option_key": "C", "hint": "I₀/8 < I₀/4, so setup I comes before setup II.", "misconception": null}, {"option_key": "D", "hint": "3I₀/8 > I₀/4, so setup III has the highest intensity and must come last.", "misconception": null}]}, "image_alt": null, "correct_answer": "A", "concept_tags": ["malus-law-comparison", "intensity-ordering"]}]'::jsonb, 'correction-batch-3');


-- Verify counts
SELECT
  q.source,
  count(DISTINCT q.id) AS questions,
  count(DISTINCT o.id) AS total_options,
  count(DISTINCT h.id) AS total_hints
FROM med_questions q
LEFT JOIN med_question_options o ON o.question_id = q.id
LEFT JOIN med_elimination_hints h ON h.question_id = q.id
WHERE q.source IN ('correction-batch-1', 'correction-batch-2', 'correction-batch-3')
GROUP BY q.source
ORDER BY q.source;

COMMIT;
